window.BIBLE["Hebrews"] = {"1":{"chapter":"1","title":"GOD HAS SPOKEN BY HIS SON","verses":{"1":{"text":"God, who at sundry times and in divers manners spake in time past unto the fathers by the prophets,","ref":"Hebrews 1:1","synthesized":"God, who at sundry times and in divers manners spake in time past unto the fathers by the prophets,","sources":{"KJV":{"text":"God, who at sundry times and in divers manners spake in time past unto the fathers by the prophets,"}},"definableWords":["God","fathers"],"peopleInVerse":[]},"2":{"text":"Hath in these last days spoken unto us by his Son, whom he hath appointed heir of all things, by whom also he made the worlds;","ref":"Hebrews 1:2","synthesized":"Hath in these last days spoken unto us by his Son, whom he hath appointed heir of all things, by whom also he made the worlds;","sources":{"KJV":{"text":"Hath in these last days spoken unto us by his Son, whom he hath appointed heir of all things, by whom also he made the worlds;"}},"definableWords":["days","son","made"],"peopleInVerse":[]},"3":{"text":"Who being the brightness of his glory, and the express image of his person, and upholding all things by the word of his power, when he had by himself purged our sins, sat down on the right hand of the Majesty on high;","ref":"Hebrews 1:3","synthesized":"Who being the brightness of his glory, and the express image of his person, and upholding all things by the word of his power, when he had by himself purged our sins, sat down on the right hand of the Majesty on high;","sources":{"KJV":{"text":"Who being the brightness of his glory, and the express image of his person, and upholding all things by the word of his power, when he had by himself purged our sins, sat down on the right hand of the Majesty on high;"}},"definableWords":["image","word"],"peopleInVerse":[]},"4":{"text":"Being made so much better than the angels, as he hath by inheritance obtained a more excellent name than they.","ref":"Hebrews 1:4","synthesized":"Being made so much better than the angels, as he hath by inheritance obtained a more excellent name than they.","sources":{"KJV":{"text":"Being made so much better than the angels, as he hath by inheritance obtained a more excellent name than they."}},"definableWords":["made","name"],"peopleInVerse":[]},"5":{"text":"For unto which of the angels said he at any time, Thou art my Son, this day have I begotten thee? And again, I will be to him a Father, and he shall be to me a Son?","ref":"Hebrews 1:5","synthesized":"For unto which of the angels said he at any time, Thou art my Son, this day have I begotten thee? And again, I will be to him a Father, and he shall be to me a Son?","sources":{"KJV":{"text":"For unto which of the angels said he at any time, Thou art my Son, this day have I begotten thee? And again, I will be to him a Father, and he shall be to me a Son?"}},"definableWords":["son","day","father"],"peopleInVerse":[]},"6":{"text":"And again, when he bringeth in the firstbegotten into the world, he saith, And let all the angels of God worship him.","ref":"Hebrews 1:6","synthesized":"And again, when he bringeth in the firstbegotten into the world, he saith, And let all the angels of God worship him.","sources":{"KJV":{"text":"And again, when he bringeth in the firstbegotten into the world, he saith, And let all the angels of God worship him."}},"definableWords":["God"],"peopleInVerse":[]},"7":{"text":"And of the angels he saith, Who maketh his angels spirits, and his ministers a flame of fire.","ref":"Hebrews 1:7","synthesized":"And of the angels he saith, Who maketh his angels spirits, and his ministers a flame of fire.","sources":{"KJV":{"text":"And of the angels he saith, Who maketh his angels spirits, and his ministers a flame of fire."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"But unto the Son he saith, Thy throne, O God, is for ever and ever: a sceptre of righteousness is the sceptre of thy kingdom.","ref":"Hebrews 1:8","synthesized":"But unto the Son he saith, Thy throne, O God, is for ever and ever: a sceptre of righteousness is the sceptre of thy kingdom.","sources":{"KJV":{"text":"But unto the Son he saith, Thy throne, O God, is for ever and ever: a sceptre of righteousness is the sceptre of thy kingdom."}},"definableWords":["son","throne","God","righteousness","kingdom"],"peopleInVerse":[]},"9":{"text":"Thou hast loved righteousness, and hated iniquity; therefore God, even thy God, hath anointed thee with the oil of gladness above thy fellows.","ref":"Hebrews 1:9","synthesized":"Thou hast loved righteousness, and hated iniquity; therefore God, even thy God, hath anointed thee with the oil of gladness above thy fellows.","sources":{"KJV":{"text":"Thou hast loved righteousness, and hated iniquity; therefore God, even thy God, hath anointed thee with the oil of gladness above thy fellows."}},"definableWords":["righteousness","iniquity","God"],"peopleInVerse":[]},"10":{"text":"And, Thou, Lord, in the beginning hast laid the foundation of the earth; and the heavens are the works of thine hands:","ref":"Hebrews 1:10","synthesized":"And, Thou, Lord, in the beginning hast laid the foundation of the earth; and the heavens are the works of thine hands:","sources":{"KJV":{"text":"And, Thou, Lord, in the beginning hast laid the foundation of the earth; and the heavens are the works of thine hands:"}},"definableWords":["Lord","beginning","earth","heavens","works"],"peopleInVerse":[]},"11":{"text":"They shall perish; but thou remainest; and they all shall wax old as doth a garment;","ref":"Hebrews 1:11","synthesized":"They shall perish; but thou remainest; and they all shall wax old as doth a garment;","sources":{"KJV":{"text":"They shall perish; but thou remainest; and they all shall wax old as doth a garment;"}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"And as a vesture shalt thou fold them up, and they shall be changed: but thou art the same, and thy years shall not fail.","ref":"Hebrews 1:12","synthesized":"And as a vesture shalt thou fold them up, and they shall be changed: but thou art the same, and thy years shall not fail.","sources":{"KJV":{"text":"And as a vesture shalt thou fold them up, and they shall be changed: but thou art the same, and thy years shall not fail."}},"definableWords":["years"],"peopleInVerse":[]},"13":{"text":"But to which of the angels said he at any time, Sit on my right hand, until I make thine enemies thy footstool?","ref":"Hebrews 1:13","synthesized":"But to which of the angels said he at any time, Sit on my right hand, until I make thine enemies thy footstool?","sources":{"KJV":{"text":"But to which of the angels said he at any time, Sit on my right hand, until I make thine enemies thy footstool?"}},"definableWords":["make"],"peopleInVerse":[]},"14":{"text":"Are they not all ministering spirits, sent forth to minister for them who shall be heirs of salvation?","ref":"Hebrews 1:14","synthesized":"Are they not all ministering spirits, sent forth to minister for them who shall be heirs of salvation?","sources":{"KJV":{"text":"Are they not all ministering spirits, sent forth to minister for them who shall be heirs of salvation?"}},"definableWords":[],"peopleInVerse":[]}}},"2":{"chapter":"2","title":"Hebrews 2","verses":{"1":{"text":"Therefore we ought to give the more earnest heed to the things which we have heard, lest at any time we should let them slip.","ref":"Hebrews 2:1","synthesized":"Therefore we ought to give the more earnest heed to the things which we have heard, lest at any time we should let them slip.","sources":{"KJV":{"text":"Therefore we ought to give the more earnest heed to the things which we have heard, lest at any time we should let them slip."}},"definableWords":[],"peopleInVerse":[]},"2":{"text":"For if the word spoken by angels was stedfast, and every transgression and disobedience received a just recompence of reward;","ref":"Hebrews 2:2","synthesized":"For if the word spoken by angels was stedfast, and every transgression and disobedience received a just recompence of reward;","sources":{"KJV":{"text":"For if the word spoken by angels was stedfast, and every transgression and disobedience received a just recompence of reward;"}},"definableWords":["word","transgression"],"peopleInVerse":[]},"3":{"text":"How shall we escape, if we neglect so great salvation; which at the first began to be spoken by the Lord, and was confirmed unto us by them that heard him;","ref":"Hebrews 2:3","synthesized":"How shall we escape, if we neglect so great salvation; which at the first began to be spoken by the Lord, and was confirmed unto us by them that heard him;","sources":{"KJV":{"text":"How shall we escape, if we neglect so great salvation; which at the first began to be spoken by the Lord, and was confirmed unto us by them that heard him;"}},"definableWords":["great","Lord"],"peopleInVerse":[]},"4":{"text":"God also bearing them witness, both with signs and wonders, and with divers miracles, and gifts of the Holy Ghost, according to his own will?","ref":"Hebrews 2:4","synthesized":"God also bearing them witness, both with signs and wonders, and with divers miracles, and gifts of the Holy Ghost, according to his own will?","sources":{"KJV":{"text":"God also bearing them witness, both with signs and wonders, and with divers miracles, and gifts of the Holy Ghost, according to his own will?"}},"definableWords":["God"],"peopleInVerse":[]},"5":{"text":"For unto the angels hath he not put in subjection the world to come, whereof we speak.","ref":"Hebrews 2:5","synthesized":"For unto the angels hath he not put in subjection the world to come, whereof we speak.","sources":{"KJV":{"text":"For unto the angels hath he not put in subjection the world to come, whereof we speak."}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"But one in a certain place testified, saying, What is man, that thou art mindful of him? or the son of man, that thou visitest him?","ref":"Hebrews 2:6","synthesized":"But one in a certain place testified, saying, What is man, that thou art mindful of him? or the son of man, that thou visitest him?","sources":{"KJV":{"text":"But one in a certain place testified, saying, What is man, that thou art mindful of him? or the son of man, that thou visitest him?"}},"definableWords":["one","man","or","son"],"peopleInVerse":[]},"7":{"text":"Thou madest him a little lower than the angels; thou crownedst him with glory and honour, and didst set him over the works of thy hands:","ref":"Hebrews 2:7","synthesized":"Thou madest him a little lower than the angels; thou crownedst him with glory and honour, and didst set him over the works of thy hands:","sources":{"KJV":{"text":"Thou madest him a little lower than the angels; thou crownedst him with glory and honour, and didst set him over the works of thy hands:"}},"definableWords":["works"],"peopleInVerse":[]},"8":{"text":"Thou hast put all things in subjection under his feet. For in that he put all in subjection under him, he left nothing that is not put under him. But now we see not yet all things put under him.","ref":"Hebrews 2:8","synthesized":"Thou hast put all things in subjection under his feet. For in that he put all in subjection under him, he left nothing that is not put under him. But now we see not yet all things put under him.","sources":{"KJV":{"text":"Thou hast put all things in subjection under his feet. For in that he put all in subjection under him, he left nothing that is not put under him. But now we see not yet all things put under him."}},"definableWords":["see"],"peopleInVerse":[]},"9":{"text":"But we see Jesus, who was made a little lower than the angels for the suffering of death, crowned with glory and honour; that he by the grace of God should taste death for every man.","ref":"Hebrews 2:9","synthesized":"But we see Jesus, who was made a little lower than the angels for the suffering of death, crowned with glory and honour; that he by the grace of God should taste death for every man.","sources":{"KJV":{"text":"But we see Jesus, who was made a little lower than the angels for the suffering of death, crowned with glory and honour; that he by the grace of God should taste death for every man."}},"definableWords":["see","made","death","God","man"],"peopleInVerse":["Jesus"]},"10":{"text":"For it became him, for whom are all things, and by whom are all things, in bringing many sons unto glory, to make the captain of their salvation perfect through sufferings.","ref":"Hebrews 2:10","synthesized":"For it became him, for whom are all things, and by whom are all things, in bringing many sons unto glory, to make the captain of their salvation perfect through sufferings.","sources":{"KJV":{"text":"For it became him, for whom are all things, and by whom are all things, in bringing many sons unto glory, to make the captain of their salvation perfect through sufferings."}},"definableWords":["sons","make"],"peopleInVerse":[]},"11":{"text":"For both he that sanctifieth and they who are sanctified are all of one: for which cause he is not ashamed to call them brethren,","ref":"Hebrews 2:11","synthesized":"For both he that sanctifieth and they who are sanctified are all of one: for which cause he is not ashamed to call them brethren,","sources":{"KJV":{"text":"For both he that sanctifieth and they who are sanctified are all of one: for which cause he is not ashamed to call them brethren,"}},"definableWords":["one","brethren"],"peopleInVerse":[]},"12":{"text":"Saying, I will declare thy name unto my brethren, in the midst of the church will I sing praise unto thee.","ref":"Hebrews 2:12","synthesized":"Saying, I will declare thy name unto my brethren, in the midst of the church will I sing praise unto thee.","sources":{"KJV":{"text":"Saying, I will declare thy name unto my brethren, in the midst of the church will I sing praise unto thee."}},"definableWords":["name","brethren"],"peopleInVerse":[]},"13":{"text":"And again, I will put my trust in him. And again, Behold I and the children which God hath given me.","ref":"Hebrews 2:13","synthesized":"And again, I will put my trust in him. And again, Behold I and the children which God hath given me.","sources":{"KJV":{"text":"And again, I will put my trust in him. And again, Behold I and the children which God hath given me."}},"definableWords":["God"],"peopleInVerse":[]},"14":{"text":"Forasmuch then as the children are partakers of flesh and blood, he also himself likewise took part of the same; that through death he might destroy him that had the power of death, that is, the devil;","ref":"Hebrews 2:14","synthesized":"Forasmuch then as the children are partakers of flesh and blood, he also himself likewise took part of the same; that through death he might destroy him that had the power of death, that is, the devil;","sources":{"KJV":{"text":"Forasmuch then as the children are partakers of flesh and blood, he also himself likewise took part of the same; that through death he might destroy him that had the power of death, that is, the devil;"}},"definableWords":["flesh","blood","death"],"peopleInVerse":[]},"15":{"text":"And deliver them who through fear of death were all their lifetime subject to bondage.","ref":"Hebrews 2:15","synthesized":"And deliver them who through fear of death were all their lifetime subject to bondage.","sources":{"KJV":{"text":"And deliver them who through fear of death were all their lifetime subject to bondage."}},"definableWords":["fear","death"],"peopleInVerse":[]},"16":{"text":"For verily he took not on him the nature of angels; but he took on him the seed of Abraham.","ref":"Hebrews 2:16","synthesized":"For verily he took not on him the nature of angels; but he took on him the seed of Abraham.","sources":{"KJV":{"text":"For verily he took not on him the nature of angels; but he took on him the seed of Abraham."}},"definableWords":["seed","Abraham"],"peopleInVerse":["Abraham"]},"17":{"text":"Wherefore in all things it behoved him to be made like unto his brethren, that he might be a merciful and faithful high priest in things pertaining to God, to make reconciliation for the sins of the people.","ref":"Hebrews 2:17","synthesized":"Wherefore in all things it behoved him to be made like unto his brethren, that he might be a merciful and faithful high priest in things pertaining to God, to make reconciliation for the sins of the people.","sources":{"KJV":{"text":"Wherefore in all things it behoved him to be made like unto his brethren, that he might be a merciful and faithful high priest in things pertaining to God, to make reconciliation for the sins of the people."}},"definableWords":["made","brethren","God","make","people"],"peopleInVerse":[]},"18":{"text":"For in that he himself hath suffered being tempted, he is able to succour them that are tempted.","ref":"Hebrews 2:18","synthesized":"For in that he himself hath suffered being tempted, he is able to succour them that are tempted.","sources":{"KJV":{"text":"For in that he himself hath suffered being tempted, he is able to succour them that are tempted."}},"definableWords":[],"peopleInVerse":[]}}},"3":{"chapter":"3","title":"Hebrews 3","verses":{"1":{"text":"Wherefore, holy brethren, partakers of the heavenly calling, consider the Apostle and High Priest of our profession, Christ Jesus;","ref":"Hebrews 3:1","synthesized":"Wherefore, holy brethren, partakers of the heavenly calling, consider the Apostle and High Priest of our profession, Christ Jesus;","sources":{"KJV":{"text":"Wherefore, holy brethren, partakers of the heavenly calling, consider the Apostle and High Priest of our profession, Christ Jesus;"}},"definableWords":["brethren"],"peopleInVerse":["Jesus"]},"2":{"text":"Who was faithful to him that appointed him, as also Moses was faithful in all his house.","ref":"Hebrews 3:2","synthesized":"Who was faithful to him that appointed him, as also Moses was faithful in all his house.","sources":{"KJV":{"text":"Who was faithful to him that appointed him, as also Moses was faithful in all his house."}},"definableWords":["house"],"peopleInVerse":["Moses"]},"3":{"text":"For this man was counted worthy of more glory than Moses, inasmuch as he who hath builded the house hath more honour than the house.","ref":"Hebrews 3:3","synthesized":"For this man was counted worthy of more glory than Moses, inasmuch as he who hath builded the house hath more honour than the house.","sources":{"KJV":{"text":"For this man was counted worthy of more glory than Moses, inasmuch as he who hath builded the house hath more honour than the house."}},"definableWords":["man","house"],"peopleInVerse":["Moses"]},"4":{"text":"For every house is builded by some man; but he that built all things is God.","ref":"Hebrews 3:4","synthesized":"For every house is builded by some man; but he that built all things is God.","sources":{"KJV":{"text":"For every house is builded by some man; but he that built all things is God."}},"definableWords":["house","man","God"],"peopleInVerse":[]},"5":{"text":"And Moses verily was faithful in all his house, as a servant, for a testimony of those things which were to be spoken after;","ref":"Hebrews 3:5","synthesized":"And Moses verily was faithful in all his house, as a servant, for a testimony of those things which were to be spoken after;","sources":{"KJV":{"text":"And Moses verily was faithful in all his house, as a servant, for a testimony of those things which were to be spoken after;"}},"definableWords":["house","servant"],"peopleInVerse":["Moses"]},"6":{"text":"But Christ as a son over his own house; whose house are we, if we hold fast the confidence and the rejoicing of the hope firm unto the end.","ref":"Hebrews 3:6","synthesized":"But Christ as a son over his own house; whose house are we, if we hold fast the confidence and the rejoicing of the hope firm unto the end.","sources":{"KJV":{"text":"But Christ as a son over his own house; whose house are we, if we hold fast the confidence and the rejoicing of the hope firm unto the end."}},"definableWords":["son","house"],"peopleInVerse":[]},"7":{"text":"Wherefore (as the Holy Ghost saith, To day if ye will hear his voice,","ref":"Hebrews 3:7","synthesized":"Wherefore (as the Holy Ghost saith, To day if ye will hear his voice,","sources":{"KJV":{"text":"Wherefore (as the Holy Ghost saith, To day if ye will hear his voice,"}},"definableWords":["day","voice"],"peopleInVerse":[]},"8":{"text":"Harden not your hearts, as in the provocation, in the day of temptation in the wilderness:","ref":"Hebrews 3:8","synthesized":"Harden not your hearts, as in the provocation, in the day of temptation in the wilderness:","sources":{"KJV":{"text":"Harden not your hearts, as in the provocation, in the day of temptation in the wilderness:"}},"definableWords":["day"],"peopleInVerse":[]},"9":{"text":"When your fathers tempted me, proved me, and saw my works forty years.","ref":"Hebrews 3:9","synthesized":"When your fathers tempted me, proved me, and saw my works forty years.","sources":{"KJV":{"text":"When your fathers tempted me, proved me, and saw my works forty years."}},"definableWords":["fathers","saw","works","years"],"peopleInVerse":[]},"10":{"text":"Wherefore I was grieved with that generation, and said, They do alway err in their heart; and they have not known my ways.","ref":"Hebrews 3:10","synthesized":"Wherefore I was grieved with that generation, and said, They do alway err in their heart; and they have not known my ways.","sources":{"KJV":{"text":"Wherefore I was grieved with that generation, and said, They do alway err in their heart; and they have not known my ways."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"So I sware in my wrath, They shall not enter into my rest.)","ref":"Hebrews 3:11","synthesized":"So I sware in my wrath, They shall not enter into my rest.)","sources":{"KJV":{"text":"So I sware in my wrath, They shall not enter into my rest.)"}},"definableWords":["wrath","rest"],"peopleInVerse":[]},"12":{"text":"Take heed, brethren, lest there be in any of you an evil heart of unbelief, in departing from the living God.","ref":"Hebrews 3:12","synthesized":"Take heed, brethren, lest there be in any of you an evil heart of unbelief, in departing from the living God.","sources":{"KJV":{"text":"Take heed, brethren, lest there be in any of you an evil heart of unbelief, in departing from the living God."}},"definableWords":["brethren","evil","living","God"],"peopleInVerse":[]},"13":{"text":"But exhort one another daily, while it is called To day; lest any of you be hardened through the deceitfulness of sin.","ref":"Hebrews 3:13","synthesized":"But exhort one another daily, while it is called To day; lest any of you be hardened through the deceitfulness of sin.","sources":{"KJV":{"text":"But exhort one another daily, while it is called To day; lest any of you be hardened through the deceitfulness of sin."}},"definableWords":["one","day","sin"],"peopleInVerse":[]},"14":{"text":"For we are made partakers of Christ, if we hold the beginning of our confidence stedfast unto the end;","ref":"Hebrews 3:14","synthesized":"For we are made partakers of Christ, if we hold the beginning of our confidence stedfast unto the end;","sources":{"KJV":{"text":"For we are made partakers of Christ, if we hold the beginning of our confidence stedfast unto the end;"}},"definableWords":["made","beginning"],"peopleInVerse":[]},"15":{"text":"While it is said, To day if ye will hear his voice, harden not your hearts, as in the provocation.","ref":"Hebrews 3:15","synthesized":"While it is said, To day if ye will hear his voice, harden not your hearts, as in the provocation.","sources":{"KJV":{"text":"While it is said, To day if ye will hear his voice, harden not your hearts, as in the provocation."}},"definableWords":["day","voice"],"peopleInVerse":[]},"16":{"text":"For some, when they had heard, did provoke: howbeit not all that came out of Egypt by Moses.","ref":"Hebrews 3:16","synthesized":"For some, when they had heard, did provoke: howbeit not all that came out of Egypt by Moses.","sources":{"KJV":{"text":"For some, when they had heard, did provoke: howbeit not all that came out of Egypt by Moses."}},"definableWords":["Egypt"],"peopleInVerse":["Moses"]},"17":{"text":"But with whom was he grieved forty years? was it not with them that had sinned, whose carcases fell in the wilderness?","ref":"Hebrews 3:17","synthesized":"But with whom was he grieved forty years? was it not with them that had sinned, whose carcases fell in the wilderness?","sources":{"KJV":{"text":"But with whom was he grieved forty years? was it not with them that had sinned, whose carcases fell in the wilderness?"}},"definableWords":["years"],"peopleInVerse":[]},"18":{"text":"And to whom sware he that they should not enter into his rest, but to them that believed not?","ref":"Hebrews 3:18","synthesized":"And to whom sware he that they should not enter into his rest, but to them that believed not?","sources":{"KJV":{"text":"And to whom sware he that they should not enter into his rest, but to them that believed not?"}},"definableWords":["rest","believed"],"peopleInVerse":[]},"19":{"text":"So we see that they could not enter in because of unbelief.","ref":"Hebrews 3:19","synthesized":"So we see that they could not enter in because of unbelief.","sources":{"KJV":{"text":"So we see that they could not enter in because of unbelief."}},"definableWords":["see"],"peopleInVerse":[]}}},"4":{"chapter":"4","title":"ENTER INTO HIS REST","verses":{"1":{"text":"Let us therefore fear, lest, a promise being left us of entering into his rest, any of you should seem to come short of it.","ref":"Hebrews 4:1","synthesized":"Let us therefore fear, lest, a promise being left us of entering into his rest, any of you should seem to come short of it.","sources":{"KJV":{"text":"Let us therefore fear, lest, a promise being left us of entering into his rest, any of you should seem to come short of it."}},"definableWords":["fear","promise","rest"],"peopleInVerse":[]},"2":{"text":"For unto us was the gospel preached, as well as unto them: but the word preached did not profit them, not being mixed with faith in them that heard it.","ref":"Hebrews 4:2","synthesized":"For unto us was the gospel preached, as well as unto them: but the word preached did not profit them, not being mixed with faith in them that heard it.","sources":{"KJV":{"text":"For unto us was the gospel preached, as well as unto them: but the word preached did not profit them, not being mixed with faith in them that heard it."}},"definableWords":["word","faith"],"peopleInVerse":[]},"3":{"text":"For we which have believed do enter into rest, as he said, As I have sworn in my wrath, if they shall enter into my rest: although the works were finished from the foundation of the world.","ref":"Hebrews 4:3","synthesized":"For we which have believed do enter into rest, as he said, As I have sworn in my wrath, if they shall enter into my rest: although the works were finished from the foundation of the world.","sources":{"KJV":{"text":"For we which have believed do enter into rest, as he said, As I have sworn in my wrath, if they shall enter into my rest: although the works were finished from the foundation of the world."}},"definableWords":["believed","rest","wrath","works"],"peopleInVerse":[]},"4":{"text":"For he spake in a certain place of the seventh day on this wise, And God did rest the seventh day from all his works.","ref":"Hebrews 4:4","synthesized":"For he spake in a certain place of the seventh day on this wise, And God did rest the seventh day from all his works.","sources":{"KJV":{"text":"For he spake in a certain place of the seventh day on this wise, And God did rest the seventh day from all his works."}},"definableWords":["day","God","rest","works"],"peopleInVerse":[]},"5":{"text":"And in this place again, If they shall enter into my rest.","ref":"Hebrews 4:5","synthesized":"And in this place again, If they shall enter into my rest.","sources":{"KJV":{"text":"And in this place again, If they shall enter into my rest."}},"definableWords":["rest"],"peopleInVerse":[]},"6":{"text":"Seeing therefore it remaineth that some must enter therein, and they to whom it was first preached entered not in because of unbelief:","ref":"Hebrews 4:6","synthesized":"Seeing therefore it remaineth that some must enter therein, and they to whom it was first preached entered not in because of unbelief:","sources":{"KJV":{"text":"Seeing therefore it remaineth that some must enter therein, and they to whom it was first preached entered not in because of unbelief:"}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"Again, he limiteth a certain day, saying in David, To day, after so long a time; as it is said, To day if ye will hear his voice, harden not your hearts.","ref":"Hebrews 4:7","synthesized":"Again, he limiteth a certain day, saying in David, To day, after so long a time; as it is said, To day if ye will hear his voice, harden not your hearts.","sources":{"KJV":{"text":"Again, he limiteth a certain day, saying in David, To day, after so long a time; as it is said, To day if ye will hear his voice, harden not your hearts."}},"definableWords":["day","voice"],"peopleInVerse":["David"]},"8":{"text":"For if Jesus had given them rest, then would he not afterward have spoken of another day.","ref":"Hebrews 4:8","synthesized":"For if Jesus had given them rest, then would he not afterward have spoken of another day.","sources":{"KJV":{"text":"For if Jesus had given them rest, then would he not afterward have spoken of another day."}},"definableWords":["rest","day"],"peopleInVerse":["Jesus"]},"9":{"text":"There remaineth therefore a rest to the people of God.","ref":"Hebrews 4:9","synthesized":"There remaineth therefore a rest to the people of God.","sources":{"KJV":{"text":"There remaineth therefore a rest to the people of God."}},"definableWords":["rest","people","God"],"peopleInVerse":[]},"10":{"text":"For he that is entered into his rest, he also hath ceased from his own works, as God did from his.","ref":"Hebrews 4:10","synthesized":"For he that is entered into his rest, he also hath ceased from his own works, as God did from his.","sources":{"KJV":{"text":"For he that is entered into his rest, he also hath ceased from his own works, as God did from his."}},"definableWords":["rest","works","God"],"peopleInVerse":[]},"11":{"text":"Let us labour therefore to enter into that rest, lest any man fall after the same example of unbelief.","ref":"Hebrews 4:11","synthesized":"Let us labour therefore to enter into that rest, lest any man fall after the same example of unbelief.","sources":{"KJV":{"text":"Let us labour therefore to enter into that rest, lest any man fall after the same example of unbelief."}},"definableWords":["rest","man"],"peopleInVerse":[]},"12":{"text":"For the word of God is quick, and powerful, and sharper than any twoedged sword, piercing even to the dividing asunder of soul and spirit, and of the joints and marrow, and is a discerner of the thoughts and intents of the heart.","ref":"Hebrews 4:12","synthesized":"For the word of God is quick, and powerful, and sharper than any twoedged sword, piercing even to the dividing asunder of soul and spirit, and of the joints and marrow, and is a discerner of the thoughts and intents of the heart.","sources":{"KJV":{"text":"For the word of God is quick, and powerful, and sharper than any twoedged sword, piercing even to the dividing asunder of soul and spirit, and of the joints and marrow, and is a discerner of the thoughts and intents of the heart."}},"definableWords":["word","God","soul","spirit"],"peopleInVerse":[]},"13":{"text":"Neither is there any creature that is not manifest in his sight: but all things are naked and opened unto the eyes of him with whom we have to do.","ref":"Hebrews 4:13","synthesized":"Neither is there any creature that is not manifest in his sight: but all things are naked and opened unto the eyes of him with whom we have to do.","sources":{"KJV":{"text":"Neither is there any creature that is not manifest in his sight: but all things are naked and opened unto the eyes of him with whom we have to do."}},"definableWords":["naked"],"peopleInVerse":[]},"14":{"text":"Seeing then that we have a great high priest, that is passed into the heavens, Jesus the Son of God, let us hold fast our profession.","ref":"Hebrews 4:14","synthesized":"Seeing then that we have a great high priest, that is passed into the heavens, Jesus the Son of God, let us hold fast our profession.","sources":{"KJV":{"text":"Seeing then that we have a great high priest, that is passed into the heavens, Jesus the Son of God, let us hold fast our profession."}},"definableWords":["great","heavens","son","God"],"peopleInVerse":["Jesus"]},"15":{"text":"For we have not an high priest which cannot be touched with the feeling of our infirmities; but was in all points tempted like as we are, yet without sin.","ref":"Hebrews 4:15","synthesized":"For we have not an high priest which cannot be touched with the feeling of our infirmities; but was in all points tempted like as we are, yet without sin.","sources":{"KJV":{"text":"For we have not an high priest which cannot be touched with the feeling of our infirmities; but was in all points tempted like as we are, yet without sin."}},"definableWords":["sin"],"peopleInVerse":[]},"16":{"text":"Let us therefore come boldly unto the throne of grace, that we may obtain mercy, and find grace to help in time of need.","ref":"Hebrews 4:16","synthesized":"Let us therefore come boldly unto the throne of grace, that we may obtain mercy, and find grace to help in time of need.","sources":{"KJV":{"text":"Let us therefore come boldly unto the throne of grace, that we may obtain mercy, and find grace to help in time of need."}},"definableWords":["throne","mercy"],"peopleInVerse":[]}}},"5":{"chapter":"5","title":"Hebrews 5","verses":{"1":{"text":"For every high priest taken from among men is ordained for men in things pertaining to God, that he may offer both gifts and sacrifices for sins:","ref":"Hebrews 5:1","synthesized":"For every high priest taken from among men is ordained for men in things pertaining to God, that he may offer both gifts and sacrifices for sins:","sources":{"KJV":{"text":"For every high priest taken from among men is ordained for men in things pertaining to God, that he may offer both gifts and sacrifices for sins:"}},"definableWords":["men","God"],"peopleInVerse":[]},"2":{"text":"Who can have compassion on the ignorant, and on them that are out of the way; for that he himself also is compassed with infirmity.","ref":"Hebrews 5:2","synthesized":"Who can have compassion on the ignorant, and on them that are out of the way; for that he himself also is compassed with infirmity.","sources":{"KJV":{"text":"Who can have compassion on the ignorant, and on them that are out of the way; for that he himself also is compassed with infirmity."}},"definableWords":["way"],"peopleInVerse":[]},"3":{"text":"And by reason hereof he ought, as for the people, so also for himself, to offer for sins.","ref":"Hebrews 5:3","synthesized":"And by reason hereof he ought, as for the people, so also for himself, to offer for sins.","sources":{"KJV":{"text":"And by reason hereof he ought, as for the people, so also for himself, to offer for sins."}},"definableWords":["people"],"peopleInVerse":[]},"4":{"text":"And no man taketh this honour unto himself, but he that is called of God, as was Aaron.","ref":"Hebrews 5:4","synthesized":"And no man taketh this honour unto himself, but he that is called of God, as was Aaron.","sources":{"KJV":{"text":"And no man taketh this honour unto himself, but he that is called of God, as was Aaron."}},"definableWords":["man","God"],"peopleInVerse":["Aaron"]},"5":{"text":"So also Christ glorified not himself to be made an high priest; but he that said unto him, Thou art my Son, to day have I begotten thee.","ref":"Hebrews 5:5","synthesized":"So also Christ glorified not himself to be made an high priest; but he that said unto him, Thou art my Son, to day have I begotten thee.","sources":{"KJV":{"text":"So also Christ glorified not himself to be made an high priest; but he that said unto him, Thou art my Son, to day have I begotten thee."}},"definableWords":["made","son","day"],"peopleInVerse":[]},"6":{"text":"As he saith also in another place, Thou art a priest for ever after the order of Melchisedec.","ref":"Hebrews 5:6","synthesized":"As he saith also in another place, Thou art a priest for ever after the order of Melchisedec.","sources":{"KJV":{"text":"As he saith also in another place, Thou art a priest for ever after the order of Melchisedec."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"Who in the days of his flesh, when he had offered up prayers and supplications with strong crying and tears unto him that was able to save him from death, and was heard in that he feared;","ref":"Hebrews 5:7","synthesized":"Who in the days of his flesh, when he had offered up prayers and supplications with strong crying and tears unto him that was able to save him from death, and was heard in that he feared;","sources":{"KJV":{"text":"Who in the days of his flesh, when he had offered up prayers and supplications with strong crying and tears unto him that was able to save him from death, and was heard in that he feared;"}},"definableWords":["days","flesh","strong","death"],"peopleInVerse":[]},"8":{"text":"Though he were a Son, yet learned he obedience by the things which he suffered;","ref":"Hebrews 5:8","synthesized":"Though he were a Son, yet learned he obedience by the things which he suffered;","sources":{"KJV":{"text":"Though he were a Son, yet learned he obedience by the things which he suffered;"}},"definableWords":["son"],"peopleInVerse":[]},"9":{"text":"And being made perfect, he became the author of eternal salvation unto all them that obey him;","ref":"Hebrews 5:9","synthesized":"And being made perfect, he became the author of eternal salvation unto all them that obey him;","sources":{"KJV":{"text":"And being made perfect, he became the author of eternal salvation unto all them that obey him;"}},"definableWords":["made"],"peopleInVerse":[]},"10":{"text":"Called of God an high priest after the order of Melchisedec.","ref":"Hebrews 5:10","synthesized":"Called of God an high priest after the order of Melchisedec.","sources":{"KJV":{"text":"Called of God an high priest after the order of Melchisedec."}},"definableWords":["God"],"peopleInVerse":[]},"11":{"text":"Of whom we have many things to say, and hard to be uttered, seeing ye are dull of hearing.","ref":"Hebrews 5:11","synthesized":"Of whom we have many things to say, and hard to be uttered, seeing ye are dull of hearing.","sources":{"KJV":{"text":"Of whom we have many things to say, and hard to be uttered, seeing ye are dull of hearing."}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"For when for the time ye ought to be teachers, ye have need that one teach you again which be the first principles of the oracles of God; and are become such as have need of milk, and not of strong meat.","ref":"Hebrews 5:12","synthesized":"For when for the time ye ought to be teachers, ye have need that one teach you again which be the first principles of the oracles of God; and are become such as have need of milk, and not of strong meat.","sources":{"KJV":{"text":"For when for the time ye ought to be teachers, ye have need that one teach you again which be the first principles of the oracles of God; and are become such as have need of milk, and not of strong meat."}},"definableWords":["one","God","strong"],"peopleInVerse":[]},"13":{"text":"For every one that useth milk is unskilful in the word of righteousness: for he is a babe.","ref":"Hebrews 5:13","synthesized":"For every one that useth milk is unskilful in the word of righteousness: for he is a babe.","sources":{"KJV":{"text":"For every one that useth milk is unskilful in the word of righteousness: for he is a babe."}},"definableWords":["one","word","righteousness"],"peopleInVerse":[]},"14":{"text":"But strong meat belongeth to them that are of full age, even those who by reason of use have their senses exercised to discern both good and evil.","ref":"Hebrews 5:14","synthesized":"But strong meat belongeth to them that are of full age, even those who by reason of use have their senses exercised to discern both good and evil.","sources":{"KJV":{"text":"But strong meat belongeth to them that are of full age, even those who by reason of use have their senses exercised to discern both good and evil."}},"definableWords":["strong","good","evil"],"peopleInVerse":[]}}},"6":{"chapter":"6","title":"Hebrews 6","verses":{"1":{"text":"Therefore leaving the principles of the doctrine of Christ, let us go on unto perfection; not laying again the foundation of repentance from dead works, and of faith toward God,","ref":"Hebrews 6:1","synthesized":"Therefore leaving the principles of the doctrine of Christ, let us go on unto perfection; not laying again the foundation of repentance from dead works, and of faith toward God,","sources":{"KJV":{"text":"Therefore leaving the principles of the doctrine of Christ, let us go on unto perfection; not laying again the foundation of repentance from dead works, and of faith toward God,"}},"definableWords":["works","faith","God"],"peopleInVerse":[]},"2":{"text":"Of the doctrine of baptisms, and of laying on of hands, and of resurrection of the dead, and of eternal judgment.","ref":"Hebrews 6:2","synthesized":"Of the doctrine of baptisms, and of laying on of hands, and of resurrection of the dead, and of eternal judgment.","sources":{"KJV":{"text":"Of the doctrine of baptisms, and of laying on of hands, and of resurrection of the dead, and of eternal judgment."}},"definableWords":["judgment"],"peopleInVerse":[]},"3":{"text":"And this will we do, if God permit.","ref":"Hebrews 6:3","synthesized":"And this will we do, if God permit.","sources":{"KJV":{"text":"And this will we do, if God permit."}},"definableWords":["God"],"peopleInVerse":[]},"4":{"text":"For it is impossible for those who were once enlightened, and have tasted of the heavenly gift, and were made partakers of the Holy Ghost,","ref":"Hebrews 6:4","synthesized":"For it is impossible for those who were once enlightened, and have tasted of the heavenly gift, and were made partakers of the Holy Ghost,","sources":{"KJV":{"text":"For it is impossible for those who were once enlightened, and have tasted of the heavenly gift, and were made partakers of the Holy Ghost,"}},"definableWords":["made"],"peopleInVerse":[]},"5":{"text":"And have tasted the good word of God, and the powers of the world to come,","ref":"Hebrews 6:5","synthesized":"And have tasted the good word of God, and the powers of the world to come,","sources":{"KJV":{"text":"And have tasted the good word of God, and the powers of the world to come,"}},"definableWords":["good","word","God"],"peopleInVerse":[]},"6":{"text":"If they shall fall away, to renew them again unto repentance; seeing they crucify to themselves the Son of God afresh, and put him to an open shame.","ref":"Hebrews 6:6","synthesized":"If they shall fall away, to renew them again unto repentance; seeing they crucify to themselves the Son of God afresh, and put him to an open shame.","sources":{"KJV":{"text":"If they shall fall away, to renew them again unto repentance; seeing they crucify to themselves the Son of God afresh, and put him to an open shame."}},"definableWords":["son","God"],"peopleInVerse":[]},"7":{"text":"For the earth which drinketh in the rain that cometh oft upon it, and bringeth forth herbs meet for them by whom it is dressed, receiveth blessing from God:","ref":"Hebrews 6:7","synthesized":"For the earth which drinketh in the rain that cometh oft upon it, and bringeth forth herbs meet for them by whom it is dressed, receiveth blessing from God:","sources":{"KJV":{"text":"For the earth which drinketh in the rain that cometh oft upon it, and bringeth forth herbs meet for them by whom it is dressed, receiveth blessing from God:"}},"definableWords":["earth","blessing","God"],"peopleInVerse":[]},"8":{"text":"But that which beareth thorns and briers is rejected, and is nigh unto cursing; whose end is to be burned.","ref":"Hebrews 6:8","synthesized":"But that which beareth thorns and briers is rejected, and is nigh unto cursing; whose end is to be burned.","sources":{"KJV":{"text":"But that which beareth thorns and briers is rejected, and is nigh unto cursing; whose end is to be burned."}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"But, beloved, we are persuaded better things of you, and things that accompany salvation, though we thus speak.","ref":"Hebrews 6:9","synthesized":"But, beloved, we are persuaded better things of you, and things that accompany salvation, though we thus speak.","sources":{"KJV":{"text":"But, beloved, we are persuaded better things of you, and things that accompany salvation, though we thus speak."}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"For God is not unrighteous to forget your work and labour of love, which ye have shewed toward his name, in that ye have ministered to the saints, and do minister.","ref":"Hebrews 6:10","synthesized":"For God is not unrighteous to forget your work and labour of love, which ye have shewed toward his name, in that ye have ministered to the saints, and do minister.","sources":{"KJV":{"text":"For God is not unrighteous to forget your work and labour of love, which ye have shewed toward his name, in that ye have ministered to the saints, and do minister."}},"definableWords":["God","work","love","name"],"peopleInVerse":[]},"11":{"text":"And we desire that every one of you do shew the same diligence to the full assurance of hope unto the end:","ref":"Hebrews 6:11","synthesized":"And we desire that every one of you do shew the same diligence to the full assurance of hope unto the end:","sources":{"KJV":{"text":"And we desire that every one of you do shew the same diligence to the full assurance of hope unto the end:"}},"definableWords":["one"],"peopleInVerse":[]},"12":{"text":"That ye be not slothful, but followers of them who through faith and patience inherit the promises.","ref":"Hebrews 6:12","synthesized":"That ye be not slothful, but followers of them who through faith and patience inherit the promises.","sources":{"KJV":{"text":"That ye be not slothful, but followers of them who through faith and patience inherit the promises."}},"definableWords":["faith"],"peopleInVerse":[]},"13":{"text":"For when God made promise to Abraham, because he could swear by no greater, he sware by himself,","ref":"Hebrews 6:13","synthesized":"For when God made promise to Abraham, because he could swear by no greater, he sware by himself,","sources":{"KJV":{"text":"For when God made promise to Abraham, because he could swear by no greater, he sware by himself,"}},"definableWords":["God","made","promise","Abraham"],"peopleInVerse":["Abraham"]},"14":{"text":"Saying, Surely blessing I will bless thee, and multiplying I will multiply thee.","ref":"Hebrews 6:14","synthesized":"Saying, Surely blessing I will bless thee, and multiplying I will multiply thee.","sources":{"KJV":{"text":"Saying, Surely blessing I will bless thee, and multiplying I will multiply thee."}},"definableWords":["blessing","bless","multiply"],"peopleInVerse":[]},"15":{"text":"And so, after he had patiently endured, he obtained the promise.","ref":"Hebrews 6:15","synthesized":"And so, after he had patiently endured, he obtained the promise.","sources":{"KJV":{"text":"And so, after he had patiently endured, he obtained the promise."}},"definableWords":["promise"],"peopleInVerse":[]},"16":{"text":"For men verily swear by the greater: and an oath for confirmation is to them an end of all strife.","ref":"Hebrews 6:16","synthesized":"For men verily swear by the greater: and an oath for confirmation is to them an end of all strife.","sources":{"KJV":{"text":"For men verily swear by the greater: and an oath for confirmation is to them an end of all strife."}},"definableWords":["men"],"peopleInVerse":[]},"17":{"text":"Wherein God, willing more abundantly to shew unto the heirs of promise the immutability of his counsel, confirmed it by an oath:","ref":"Hebrews 6:17","synthesized":"Wherein God, willing more abundantly to shew unto the heirs of promise the immutability of his counsel, confirmed it by an oath:","sources":{"KJV":{"text":"Wherein God, willing more abundantly to shew unto the heirs of promise the immutability of his counsel, confirmed it by an oath:"}},"definableWords":["God","promise"],"peopleInVerse":[]},"18":{"text":"That by two immutable things, in which it was impossible for God to lie, we might have a strong consolation, who have fled for refuge to lay hold upon the hope set before us:","ref":"Hebrews 6:18","synthesized":"That by two immutable things, in which it was impossible for God to lie, we might have a strong consolation, who have fled for refuge to lay hold upon the hope set before us:","sources":{"KJV":{"text":"That by two immutable things, in which it was impossible for God to lie, we might have a strong consolation, who have fled for refuge to lay hold upon the hope set before us:"}},"definableWords":["God","strong"],"peopleInVerse":[]},"19":{"text":"Which hope we have as an anchor of the soul, both sure and stedfast, and which entereth into that within the veil;","ref":"Hebrews 6:19","synthesized":"Which hope we have as an anchor of the soul, both sure and stedfast, and which entereth into that within the veil;","sources":{"KJV":{"text":"Which hope we have as an anchor of the soul, both sure and stedfast, and which entereth into that within the veil;"}},"definableWords":["soul"],"peopleInVerse":[]},"20":{"text":"Whither the forerunner is for us entered, even Jesus, made an high priest for ever after the order of Melchisedec.","ref":"Hebrews 6:20","synthesized":"Whither the forerunner is for us entered, even Jesus, made an high priest for ever after the order of Melchisedec.","sources":{"KJV":{"text":"Whither the forerunner is for us entered, even Jesus, made an high priest for ever after the order of Melchisedec."}},"definableWords":["made"],"peopleInVerse":["Jesus"]}}},"7":{"chapter":"7","title":"MELCHIZEDEK — A PRIEST FOREVER","verses":{"1":{"text":"For this Melchisedec, king of Salem, priest of the most high God, who met Abraham returning from the slaughter of the kings, and blessed him;","ref":"Hebrews 7:1","synthesized":"For this Melchisedec, king of Salem, priest of the most high God, who met Abraham returning from the slaughter of the kings, and blessed him;","sources":{"KJV":{"text":"For this Melchisedec, king of Salem, priest of the most high God, who met Abraham returning from the slaughter of the kings, and blessed him;"}},"definableWords":["king","Salem","God","Abraham","kings","blessed"],"peopleInVerse":["Abraham"]},"2":{"text":"To whom also Abraham gave a tenth part of all; first being by interpretation King of righteousness, and after that also King of Salem, which is, King of peace;","ref":"Hebrews 7:2","synthesized":"To whom also Abraham gave a tenth part of all; first being by interpretation King of righteousness, and after that also King of Salem, which is, King of peace;","sources":{"KJV":{"text":"To whom also Abraham gave a tenth part of all; first being by interpretation King of righteousness, and after that also King of Salem, which is, King of peace;"}},"definableWords":["Abraham","King","righteousness","Salem","peace"],"peopleInVerse":["Abraham"]},"3":{"text":"Without father, without mother, without descent, having neither beginning of days, nor end of life; but made like unto the Son of God; abideth a priest continually.","ref":"Hebrews 7:3","synthesized":"Without father, without mother, without descent, having neither beginning of days, nor end of life; but made like unto the Son of God; abideth a priest continually.","sources":{"KJV":{"text":"Without father, without mother, without descent, having neither beginning of days, nor end of life; but made like unto the Son of God; abideth a priest continually."}},"definableWords":["father","mother","beginning","days","life","made","son","God"],"peopleInVerse":[]},"4":{"text":"Now consider how great this man was, unto whom even the patriarch Abraham gave the tenth of the spoils.","ref":"Hebrews 7:4","synthesized":"Now consider how great this man was, unto whom even the patriarch Abraham gave the tenth of the spoils.","sources":{"KJV":{"text":"Now consider how great this man was, unto whom even the patriarch Abraham gave the tenth of the spoils."}},"definableWords":["great","man","Abraham"],"peopleInVerse":["Abraham"]},"5":{"text":"And verily they that are of the sons of Levi, who receive the office of the priesthood, have a commandment to take tithes of the people according to the law, that is, of their brethren, though they come out of the loins of Abraham:","ref":"Hebrews 7:5","synthesized":"And verily they that are of the sons of Levi, who receive the office of the priesthood, have a commandment to take tithes of the people according to the law, that is, of their brethren, though they come out of the loins of Abraham:","sources":{"KJV":{"text":"And verily they that are of the sons of Levi, who receive the office of the priesthood, have a commandment to take tithes of the people according to the law, that is, of their brethren, though they come out of the loins of Abraham:"}},"definableWords":["sons","Levi","people","brethren","Abraham"],"peopleInVerse":["Abraham"]},"6":{"text":"But he whose descent is not counted from them received tithes of Abraham, and blessed him that had the promises.","ref":"Hebrews 7:6","synthesized":"But he whose descent is not counted from them received tithes of Abraham, and blessed him that had the promises.","sources":{"KJV":{"text":"But he whose descent is not counted from them received tithes of Abraham, and blessed him that had the promises."}},"definableWords":["Abraham","blessed"],"peopleInVerse":["Abraham"]},"7":{"text":"And without all contradiction the less is blessed of the better.","ref":"Hebrews 7:7","synthesized":"And without all contradiction the less is blessed of the better.","sources":{"KJV":{"text":"And without all contradiction the less is blessed of the better."}},"definableWords":["blessed"],"peopleInVerse":[]},"8":{"text":"And here men that die receive tithes; but there he receiveth them, of whom it is witnessed that he liveth.","ref":"Hebrews 7:8","synthesized":"And here men that die receive tithes; but there he receiveth them, of whom it is witnessed that he liveth.","sources":{"KJV":{"text":"And here men that die receive tithes; but there he receiveth them, of whom it is witnessed that he liveth."}},"definableWords":["men","die"],"peopleInVerse":[]},"9":{"text":"And as I may so say, Levi also, who receiveth tithes, payed tithes in Abraham.","ref":"Hebrews 7:9","synthesized":"And as I may so say, Levi also, who receiveth tithes, payed tithes in Abraham.","sources":{"KJV":{"text":"And as I may so say, Levi also, who receiveth tithes, payed tithes in Abraham."}},"definableWords":["Levi","Abraham"],"peopleInVerse":["Abraham"]},"10":{"text":"For he was yet in the loins of his father, when Melchisedec met him.","ref":"Hebrews 7:10","synthesized":"For he was yet in the loins of his father, when Melchisedec met him.","sources":{"KJV":{"text":"For he was yet in the loins of his father, when Melchisedec met him."}},"definableWords":["father"],"peopleInVerse":[]},"11":{"text":"If therefore perfection were by the Levitical priesthood, (for under it the people received the law,) what further need was there that another priest should rise after the order of Melchisedec, and not be called after the order of Aaron?","ref":"Hebrews 7:11","synthesized":"If therefore perfection were by the Levitical priesthood, (for under it the people received the law,) what further need was there that another priest should rise after the order of Melchisedec, and not be called after the order of Aaron?","sources":{"KJV":{"text":"If therefore perfection were by the Levitical priesthood, (for under it the people received the law,) what further need was there that another priest should rise after the order of Melchisedec, and not be called after the order of Aaron?"}},"definableWords":["people"],"peopleInVerse":["Aaron"]},"12":{"text":"For the priesthood being changed, there is made of necessity a change also of the law.","ref":"Hebrews 7:12","synthesized":"For the priesthood being changed, there is made of necessity a change also of the law.","sources":{"KJV":{"text":"For the priesthood being changed, there is made of necessity a change also of the law."}},"definableWords":["made"],"peopleInVerse":[]},"13":{"text":"For he of whom these things are spoken pertaineth to another tribe, of which no man gave attendance at the altar.","ref":"Hebrews 7:13","synthesized":"For he of whom these things are spoken pertaineth to another tribe, of which no man gave attendance at the altar.","sources":{"KJV":{"text":"For he of whom these things are spoken pertaineth to another tribe, of which no man gave attendance at the altar."}},"definableWords":["tribe","man","altar"],"peopleInVerse":[]},"14":{"text":"For it is evident that our Lord sprang out of Juda; of which tribe Moses spake nothing concerning priesthood.","ref":"Hebrews 7:14","synthesized":"For it is evident that our Lord sprang out of Juda; of which tribe Moses spake nothing concerning priesthood.","sources":{"KJV":{"text":"For it is evident that our Lord sprang out of Juda; of which tribe Moses spake nothing concerning priesthood."}},"definableWords":["Lord","tribe"],"peopleInVerse":["Moses"]},"15":{"text":"And it is yet far more evident: for that after the similitude of Melchisedec there ariseth another priest,","ref":"Hebrews 7:15","synthesized":"And it is yet far more evident: for that after the similitude of Melchisedec there ariseth another priest,","sources":{"KJV":{"text":"And it is yet far more evident: for that after the similitude of Melchisedec there ariseth another priest,"}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"Who is made, not after the law of a carnal commandment, but after the power of an endless life.","ref":"Hebrews 7:16","synthesized":"Who is made, not after the law of a carnal commandment, but after the power of an endless life.","sources":{"KJV":{"text":"Who is made, not after the law of a carnal commandment, but after the power of an endless life."}},"definableWords":["made","life"],"peopleInVerse":[]},"17":{"text":"For he testifieth, Thou art a priest for ever after the order of Melchisedec.","ref":"Hebrews 7:17","synthesized":"For he testifieth, Thou art a priest for ever after the order of Melchisedec.","sources":{"KJV":{"text":"For he testifieth, Thou art a priest for ever after the order of Melchisedec."}},"definableWords":[],"peopleInVerse":[]},"18":{"text":"For there is verily a disannulling of the commandment going before for the weakness and unprofitableness thereof.","ref":"Hebrews 7:18","synthesized":"For there is verily a disannulling of the commandment going before for the weakness and unprofitableness thereof.","sources":{"KJV":{"text":"For there is verily a disannulling of the commandment going before for the weakness and unprofitableness thereof."}},"definableWords":[],"peopleInVerse":[]},"19":{"text":"For the law made nothing perfect, but the bringing in of a better hope did; by the which we draw nigh unto God.","ref":"Hebrews 7:19","synthesized":"For the law made nothing perfect, but the bringing in of a better hope did; by the which we draw nigh unto God.","sources":{"KJV":{"text":"For the law made nothing perfect, but the bringing in of a better hope did; by the which we draw nigh unto God."}},"definableWords":["made","God"],"peopleInVerse":[]},"20":{"text":"And inasmuch as not without an oath he was made priest:","ref":"Hebrews 7:20","synthesized":"And inasmuch as not without an oath he was made priest:","sources":{"KJV":{"text":"And inasmuch as not without an oath he was made priest:"}},"definableWords":["made"],"peopleInVerse":[]},"21":{"text":"(For those priests were made without an oath; but this with an oath by him that said unto him, The Lord sware and will not repent, Thou art a priest for ever after the order of Melchisedec:)","ref":"Hebrews 7:21","synthesized":"(For those priests were made without an oath; but this with an oath by him that said unto him, The Lord sware and will not repent, Thou art a priest for ever after the order of Melchisedec:)","sources":{"KJV":{"text":"(For those priests were made without an oath; but this with an oath by him that said unto him, The Lord sware and will not repent, Thou art a priest for ever after the order of Melchisedec:)"}},"definableWords":["made","Lord"],"peopleInVerse":[]},"22":{"text":"By so much was Jesus made a surety of a better testament.","ref":"Hebrews 7:22","synthesized":"By so much was Jesus made a surety of a better testament.","sources":{"KJV":{"text":"By so much was Jesus made a surety of a better testament."}},"definableWords":["made"],"peopleInVerse":["Jesus"]},"23":{"text":"And they truly were many priests, because they were not suffered to continue by reason of death:","ref":"Hebrews 7:23","synthesized":"And they truly were many priests, because they were not suffered to continue by reason of death:","sources":{"KJV":{"text":"And they truly were many priests, because they were not suffered to continue by reason of death:"}},"definableWords":["death"],"peopleInVerse":[]},"24":{"text":"But this man, because he continueth ever, hath an unchangeable priesthood.","ref":"Hebrews 7:24","synthesized":"But this man, because he continueth ever, hath an unchangeable priesthood.","sources":{"KJV":{"text":"But this man, because he continueth ever, hath an unchangeable priesthood."}},"definableWords":["man"],"peopleInVerse":[]},"25":{"text":"Wherefore he is able also to save them to the uttermost that come unto God by him, seeing he ever liveth to make intercession for them.","ref":"Hebrews 7:25","synthesized":"Wherefore he is able also to save them to the uttermost that come unto God by him, seeing he ever liveth to make intercession for them.","sources":{"KJV":{"text":"Wherefore he is able also to save them to the uttermost that come unto God by him, seeing he ever liveth to make intercession for them."}},"definableWords":["God","make"],"peopleInVerse":[]},"26":{"text":"For such an high priest became us, who is holy, harmless, undefiled, separate from sinners, and made higher than the heavens;","ref":"Hebrews 7:26","synthesized":"For such an high priest became us, who is holy, harmless, undefiled, separate from sinners, and made higher than the heavens;","sources":{"KJV":{"text":"For such an high priest became us, who is holy, harmless, undefiled, separate from sinners, and made higher than the heavens;"}},"definableWords":["made","heavens"],"peopleInVerse":[]},"27":{"text":"Who needeth not daily, as those high priests, to offer up sacrifice, first for his own sins, and then for the people’s: for this he did once, when he offered up himself.","ref":"Hebrews 7:27","synthesized":"Who needeth not daily, as those high priests, to offer up sacrifice, first for his own sins, and then for the people’s: for this he did once, when he offered up himself.","sources":{"KJV":{"text":"Who needeth not daily, as those high priests, to offer up sacrifice, first for his own sins, and then for the people’s: for this he did once, when he offered up himself."}},"definableWords":["sacrifice","people"],"peopleInVerse":[]},"28":{"text":"For the law maketh men high priests which have infirmity; but the word of the oath, which was since the law, maketh the Son, who is consecrated for evermore.","ref":"Hebrews 7:28","synthesized":"For the law maketh men high priests which have infirmity; but the word of the oath, which was since the law, maketh the Son, who is consecrated for evermore.","sources":{"KJV":{"text":"For the law maketh men high priests which have infirmity; but the word of the oath, which was since the law, maketh the Son, who is consecrated for evermore."}},"definableWords":["men","word","son"],"peopleInVerse":[]}}},"8":{"chapter":"8","title":"A BETTER COVENANT","verses":{"1":{"text":"Now of the things which we have spoken this is the sum: We have such an high priest, who is set on the right hand of the throne of the Majesty in the heavens;","ref":"Hebrews 8:1","synthesized":"Now of the things which we have spoken this is the sum: We have such an high priest, who is set on the right hand of the throne of the Majesty in the heavens;","sources":{"KJV":{"text":"Now of the things which we have spoken this is the sum: We have such an high priest, who is set on the right hand of the throne of the Majesty in the heavens;"}},"definableWords":["throne","heavens"],"peopleInVerse":[]},"2":{"text":"A minister of the sanctuary, and of the true tabernacle, which the Lord pitched, and not man.","ref":"Hebrews 8:2","synthesized":"A minister of the sanctuary, and of the true tabernacle, which the Lord pitched, and not man.","sources":{"KJV":{"text":"A minister of the sanctuary, and of the true tabernacle, which the Lord pitched, and not man."}},"definableWords":["Lord","man"],"peopleInVerse":[]},"3":{"text":"For every high priest is ordained to offer gifts and sacrifices: wherefore it is of necessity that this man have somewhat also to offer.","ref":"Hebrews 8:3","synthesized":"For every high priest is ordained to offer gifts and sacrifices: wherefore it is of necessity that this man have somewhat also to offer.","sources":{"KJV":{"text":"For every high priest is ordained to offer gifts and sacrifices: wherefore it is of necessity that this man have somewhat also to offer."}},"definableWords":["man"],"peopleInVerse":[]},"4":{"text":"For if he were on earth, he should not be a priest, seeing that there are priests that offer gifts according to the law:","ref":"Hebrews 8:4","synthesized":"For if he were on earth, he should not be a priest, seeing that there are priests that offer gifts according to the law:","sources":{"KJV":{"text":"For if he were on earth, he should not be a priest, seeing that there are priests that offer gifts according to the law:"}},"definableWords":["earth"],"peopleInVerse":[]},"5":{"text":"Who serve unto the example and shadow of heavenly things, as Moses was admonished of God when he was about to make the tabernacle: for, See, saith he, that thou make all things according to the pattern shewed to thee in the mount.","ref":"Hebrews 8:5","synthesized":"Who serve unto the example and shadow of heavenly things, as Moses was admonished of God when he was about to make the tabernacle: for, See, saith he, that thou make all things according to the pattern shewed to thee in the mount.","sources":{"KJV":{"text":"Who serve unto the example and shadow of heavenly things, as Moses was admonished of God when he was about to make the tabernacle: for, See, saith he, that thou make all things according to the pattern shewed to thee in the mount."}},"definableWords":["God","make","see"],"peopleInVerse":["Moses"]},"6":{"text":"But now hath he obtained a more excellent ministry, by how much also he is the mediator of a better covenant, which was established upon better promises.","ref":"Hebrews 8:6","synthesized":"But now hath he obtained a more excellent ministry, by how much also he is the mediator of a better covenant, which was established upon better promises.","sources":{"KJV":{"text":"But now hath he obtained a more excellent ministry, by how much also he is the mediator of a better covenant, which was established upon better promises."}},"definableWords":["covenant"],"peopleInVerse":[]},"7":{"text":"For if that first covenant had been faultless, then should no place have been sought for the second.","ref":"Hebrews 8:7","synthesized":"For if that first covenant had been faultless, then should no place have been sought for the second.","sources":{"KJV":{"text":"For if that first covenant had been faultless, then should no place have been sought for the second."}},"definableWords":["covenant"],"peopleInVerse":[]},"8":{"text":"For finding fault with them, he saith, Behold, the days come, saith the Lord, when I will make a new covenant with the house of Israel and with the house of Judah:","ref":"Hebrews 8:8","synthesized":"For finding fault with them, he saith, Behold, the days come, saith the Lord, when I will make a new covenant with the house of Israel and with the house of Judah:","sources":{"KJV":{"text":"For finding fault with them, he saith, Behold, the days come, saith the Lord, when I will make a new covenant with the house of Israel and with the house of Judah:"}},"definableWords":["days","Lord","make","covenant","house","Israel","Judah"],"peopleInVerse":[]},"9":{"text":"Not according to the covenant that I made with their fathers in the day when I took them by the hand to lead them out of the land of Egypt; because they continued not in my covenant, and I regarded them not, saith the Lord.","ref":"Hebrews 8:9","synthesized":"Not according to the covenant that I made with their fathers in the day when I took them by the hand to lead them out of the land of Egypt; because they continued not in my covenant, and I regarded them not, saith the Lord.","sources":{"KJV":{"text":"Not according to the covenant that I made with their fathers in the day when I took them by the hand to lead them out of the land of Egypt; because they continued not in my covenant, and I regarded them not, saith the Lord."}},"definableWords":["covenant","made","fathers","day","land","Egypt","Lord"],"peopleInVerse":[]},"10":{"text":"For this is the covenant that I will make with the house of Israel after those days, saith the Lord; I will put my laws into their mind, and write them in their hearts: and I will be to them a God, and they shall be to me a people:","ref":"Hebrews 8:10","synthesized":"For this is the covenant that I will make with the house of Israel after those days, saith the Lord; I will put my laws into their mind, and write them in their hearts: and I will be to them a God, and they shall be to me a people:","sources":{"KJV":{"text":"For this is the covenant that I will make with the house of Israel after those days, saith the Lord; I will put my laws into their mind, and write them in their hearts: and I will be to them a God, and they shall be to me a people:"}},"definableWords":["covenant","make","house","Israel","days","Lord","God","people"],"peopleInVerse":[]},"11":{"text":"And they shall not teach every man his neighbour, and every man his brother, saying, Know the Lord: for all shall know me, from the least to the greatest.","ref":"Hebrews 8:11","synthesized":"And they shall not teach every man his neighbour, and every man his brother, saying, Know the Lord: for all shall know me, from the least to the greatest.","sources":{"KJV":{"text":"And they shall not teach every man his neighbour, and every man his brother, saying, Know the Lord: for all shall know me, from the least to the greatest."}},"definableWords":["man","brother","Lord"],"peopleInVerse":[]},"12":{"text":"For I will be merciful to their unrighteousness, and their sins and their iniquities will I remember no more.","ref":"Hebrews 8:12","synthesized":"For I will be merciful to their unrighteousness, and their sins and their iniquities will I remember no more.","sources":{"KJV":{"text":"For I will be merciful to their unrighteousness, and their sins and their iniquities will I remember no more."}},"definableWords":["remember"],"peopleInVerse":[]},"13":{"text":"In that he saith, A new covenant, he hath made the first old. Now that which decayeth and waxeth old is ready to vanish away.","ref":"Hebrews 8:13","synthesized":"In that he saith, A new covenant, he hath made the first old. Now that which decayeth and waxeth old is ready to vanish away.","sources":{"KJV":{"text":"In that he saith, A new covenant, he hath made the first old. Now that which decayeth and waxeth old is ready to vanish away."}},"definableWords":["covenant","made"],"peopleInVerse":[]}}},"9":{"chapter":"9","title":"THE BLOOD OF CHRIST","verses":{"1":{"text":"Then verily the first covenant had also ordinances of divine service, and a worldly sanctuary.","ref":"Hebrews 9:1","synthesized":"Then verily the first covenant had also ordinances of divine service, and a worldly sanctuary.","sources":{"KJV":{"text":"Then verily the first covenant had also ordinances of divine service, and a worldly sanctuary."}},"definableWords":["covenant"],"peopleInVerse":[]},"2":{"text":"For there was a tabernacle made; the first, wherein was the candlestick, and the table, and the shewbread; which is called the sanctuary.","ref":"Hebrews 9:2","synthesized":"For there was a tabernacle made; the first, wherein was the candlestick, and the table, and the shewbread; which is called the sanctuary.","sources":{"KJV":{"text":"For there was a tabernacle made; the first, wherein was the candlestick, and the table, and the shewbread; which is called the sanctuary."}},"definableWords":["made"],"peopleInVerse":[]},"3":{"text":"And after the second veil, the tabernacle which is called the Holiest of all;","ref":"Hebrews 9:3","synthesized":"And after the second veil, the tabernacle which is called the Holiest of all;","sources":{"KJV":{"text":"And after the second veil, the tabernacle which is called the Holiest of all;"}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"Which had the golden censer, and the ark of the covenant overlaid round about with gold, wherein was the golden pot that had manna, and Aaron’s rod that budded, and the tables of the covenant;","ref":"Hebrews 9:4","synthesized":"Which had the golden censer, and the ark of the covenant overlaid round about with gold, wherein was the golden pot that had manna, and Aaron’s rod that budded, and the tables of the covenant;","sources":{"KJV":{"text":"Which had the golden censer, and the ark of the covenant overlaid round about with gold, wherein was the golden pot that had manna, and Aaron’s rod that budded, and the tables of the covenant;"}},"definableWords":["ark","covenant"],"peopleInVerse":["Aaron"]},"5":{"text":"And over it the cherubims of glory shadowing the mercyseat; of which we cannot now speak particularly.","ref":"Hebrews 9:5","synthesized":"And over it the cherubims of glory shadowing the mercyseat; of which we cannot now speak particularly.","sources":{"KJV":{"text":"And over it the cherubims of glory shadowing the mercyseat; of which we cannot now speak particularly."}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"Now when these things were thus ordained, the priests went always into the first tabernacle, accomplishing the service of God.","ref":"Hebrews 9:6","synthesized":"Now when these things were thus ordained, the priests went always into the first tabernacle, accomplishing the service of God.","sources":{"KJV":{"text":"Now when these things were thus ordained, the priests went always into the first tabernacle, accomplishing the service of God."}},"definableWords":["God"],"peopleInVerse":[]},"7":{"text":"But into the second went the high priest alone once every year, not without blood, which he offered for himself, and for the errors of the people:","ref":"Hebrews 9:7","synthesized":"But into the second went the high priest alone once every year, not without blood, which he offered for himself, and for the errors of the people:","sources":{"KJV":{"text":"But into the second went the high priest alone once every year, not without blood, which he offered for himself, and for the errors of the people:"}},"definableWords":["year","blood","people"],"peopleInVerse":[]},"8":{"text":"The Holy Ghost this signifying, that the way into the holiest of all was not yet made manifest, while as the first tabernacle was yet standing:","ref":"Hebrews 9:8","synthesized":"The Holy Ghost this signifying, that the way into the holiest of all was not yet made manifest, while as the first tabernacle was yet standing:","sources":{"KJV":{"text":"The Holy Ghost this signifying, that the way into the holiest of all was not yet made manifest, while as the first tabernacle was yet standing:"}},"definableWords":["way","made"],"peopleInVerse":[]},"9":{"text":"Which was a figure for the time then present, in which were offered both gifts and sacrifices, that could not make him that did the service perfect, as pertaining to the conscience;","ref":"Hebrews 9:9","synthesized":"Which was a figure for the time then present, in which were offered both gifts and sacrifices, that could not make him that did the service perfect, as pertaining to the conscience;","sources":{"KJV":{"text":"Which was a figure for the time then present, in which were offered both gifts and sacrifices, that could not make him that did the service perfect, as pertaining to the conscience;"}},"definableWords":["make"],"peopleInVerse":[]},"10":{"text":"Which stood only in meats and drinks, and divers washings, and carnal ordinances, imposed on them until the time of reformation.","ref":"Hebrews 9:10","synthesized":"Which stood only in meats and drinks, and divers washings, and carnal ordinances, imposed on them until the time of reformation.","sources":{"KJV":{"text":"Which stood only in meats and drinks, and divers washings, and carnal ordinances, imposed on them until the time of reformation."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"But Christ being come an high priest of good things to come, by a greater and more perfect tabernacle, not made with hands, that is to say, not of this building;","ref":"Hebrews 9:11","synthesized":"But Christ being come an high priest of good things to come, by a greater and more perfect tabernacle, not made with hands, that is to say, not of this building;","sources":{"KJV":{"text":"But Christ being come an high priest of good things to come, by a greater and more perfect tabernacle, not made with hands, that is to say, not of this building;"}},"definableWords":["good","made"],"peopleInVerse":[]},"12":{"text":"Neither by the blood of goats and calves, but by his own blood he entered in once into the holy place, having obtained eternal redemption for us.","ref":"Hebrews 9:12","synthesized":"Neither by the blood of goats and calves, but by his own blood he entered in once into the holy place, having obtained eternal redemption for us.","sources":{"KJV":{"text":"Neither by the blood of goats and calves, but by his own blood he entered in once into the holy place, having obtained eternal redemption for us."}},"definableWords":["blood"],"peopleInVerse":[]},"13":{"text":"For if the blood of bulls and of goats, and the ashes of an heifer sprinkling the unclean, sanctifieth to the purifying of the flesh:","ref":"Hebrews 9:13","synthesized":"For if the blood of bulls and of goats, and the ashes of an heifer sprinkling the unclean, sanctifieth to the purifying of the flesh:","sources":{"KJV":{"text":"For if the blood of bulls and of goats, and the ashes of an heifer sprinkling the unclean, sanctifieth to the purifying of the flesh:"}},"definableWords":["blood","flesh"],"peopleInVerse":[]},"14":{"text":"How much more shall the blood of Christ, who through the eternal Spirit offered himself without spot to God, purge your conscience from dead works to serve the living God?","ref":"Hebrews 9:14","synthesized":"How much more shall the blood of Christ, who through the eternal Spirit offered himself without spot to God, purge your conscience from dead works to serve the living God?","sources":{"KJV":{"text":"How much more shall the blood of Christ, who through the eternal Spirit offered himself without spot to God, purge your conscience from dead works to serve the living God?"}},"definableWords":["blood","Spirit","God","works","living"],"peopleInVerse":[]},"15":{"text":"And for this cause he is the mediator of the new testament, that by means of death, for the redemption of the transgressions that were under the first testament, they which are called might receive the promise of eternal inheritance.","ref":"Hebrews 9:15","synthesized":"And for this cause he is the mediator of the new testament, that by means of death, for the redemption of the transgressions that were under the first testament, they which are called might receive the promise of eternal inheritance.","sources":{"KJV":{"text":"And for this cause he is the mediator of the new testament, that by means of death, for the redemption of the transgressions that were under the first testament, they which are called might receive the promise of eternal inheritance."}},"definableWords":["death","promise"],"peopleInVerse":[]},"16":{"text":"For where a testament is, there must also of necessity be the death of the testator.","ref":"Hebrews 9:16","synthesized":"For where a testament is, there must also of necessity be the death of the testator.","sources":{"KJV":{"text":"For where a testament is, there must also of necessity be the death of the testator."}},"definableWords":["death"],"peopleInVerse":[]},"17":{"text":"For a testament is of force after men are dead: otherwise it is of no strength at all while the testator liveth.","ref":"Hebrews 9:17","synthesized":"For a testament is of force after men are dead: otherwise it is of no strength at all while the testator liveth.","sources":{"KJV":{"text":"For a testament is of force after men are dead: otherwise it is of no strength at all while the testator liveth."}},"definableWords":["men"],"peopleInVerse":[]},"18":{"text":"Whereupon neither the first testament was dedicated without blood.","ref":"Hebrews 9:18","synthesized":"Whereupon neither the first testament was dedicated without blood.","sources":{"KJV":{"text":"Whereupon neither the first testament was dedicated without blood."}},"definableWords":["blood"],"peopleInVerse":[]},"19":{"text":"For when Moses had spoken every precept to all the people according to the law, he took the blood of calves and of goats, with water, and scarlet wool, and hyssop, and sprinkled both the book, and all the people,","ref":"Hebrews 9:19","synthesized":"For when Moses had spoken every precept to all the people according to the law, he took the blood of calves and of goats, with water, and scarlet wool, and hyssop, and sprinkled both the book, and all the people,","sources":{"KJV":{"text":"For when Moses had spoken every precept to all the people according to the law, he took the blood of calves and of goats, with water, and scarlet wool, and hyssop, and sprinkled both the book, and all the people,"}},"definableWords":["people","blood","water"],"peopleInVerse":["Moses"]},"20":{"text":"Saying, This is the blood of the testament which God hath enjoined unto you.","ref":"Hebrews 9:20","synthesized":"Saying, This is the blood of the testament which God hath enjoined unto you.","sources":{"KJV":{"text":"Saying, This is the blood of the testament which God hath enjoined unto you."}},"definableWords":["blood","God"],"peopleInVerse":[]},"21":{"text":"Moreover he sprinkled with blood both the tabernacle, and all the vessels of the ministry.","ref":"Hebrews 9:21","synthesized":"Moreover he sprinkled with blood both the tabernacle, and all the vessels of the ministry.","sources":{"KJV":{"text":"Moreover he sprinkled with blood both the tabernacle, and all the vessels of the ministry."}},"definableWords":["blood"],"peopleInVerse":[]},"22":{"text":"And almost all things are by the law purged with blood; and without shedding of blood is no remission.","ref":"Hebrews 9:22","synthesized":"And almost all things are by the law purged with blood; and without shedding of blood is no remission.","sources":{"KJV":{"text":"And almost all things are by the law purged with blood; and without shedding of blood is no remission."}},"definableWords":["blood"],"peopleInVerse":[]},"23":{"text":"It was therefore necessary that the patterns of things in the heavens should be purified with these; but the heavenly things themselves with better sacrifices than these.","ref":"Hebrews 9:23","synthesized":"It was therefore necessary that the patterns of things in the heavens should be purified with these; but the heavenly things themselves with better sacrifices than these.","sources":{"KJV":{"text":"It was therefore necessary that the patterns of things in the heavens should be purified with these; but the heavenly things themselves with better sacrifices than these."}},"definableWords":["heavens"],"peopleInVerse":[]},"24":{"text":"For Christ is not entered into the holy places made with hands, which are the figures of the true; but into heaven itself, now to appear in the presence of God for us:","ref":"Hebrews 9:24","synthesized":"For Christ is not entered into the holy places made with hands, which are the figures of the true; but into heaven itself, now to appear in the presence of God for us:","sources":{"KJV":{"text":"For Christ is not entered into the holy places made with hands, which are the figures of the true; but into heaven itself, now to appear in the presence of God for us:"}},"definableWords":["made","heaven","God"],"peopleInVerse":[]},"25":{"text":"Nor yet that he should offer himself often, as the high priest entereth into the holy place every year with blood of others;","ref":"Hebrews 9:25","synthesized":"Nor yet that he should offer himself often, as the high priest entereth into the holy place every year with blood of others;","sources":{"KJV":{"text":"Nor yet that he should offer himself often, as the high priest entereth into the holy place every year with blood of others;"}},"definableWords":["year","blood"],"peopleInVerse":[]},"26":{"text":"For then must he often have suffered since the foundation of the world: but now once in the end of the world hath he appeared to put away sin by the sacrifice of himself.","ref":"Hebrews 9:26","synthesized":"For then must he often have suffered since the foundation of the world: but now once in the end of the world hath he appeared to put away sin by the sacrifice of himself.","sources":{"KJV":{"text":"For then must he often have suffered since the foundation of the world: but now once in the end of the world hath he appeared to put away sin by the sacrifice of himself."}},"definableWords":["sin","sacrifice"],"peopleInVerse":[]},"27":{"text":"And as it is appointed unto men once to die, but after this the judgment:","ref":"Hebrews 9:27","synthesized":"And as it is appointed unto men once to die, but after this the judgment:","sources":{"KJV":{"text":"And as it is appointed unto men once to die, but after this the judgment:"}},"definableWords":["men","die","judgment"],"peopleInVerse":[]},"28":{"text":"So Christ was once offered to bear the sins of many; and unto them that look for him shall he appear the second time without sin unto salvation.","ref":"Hebrews 9:28","synthesized":"So Christ was once offered to bear the sins of many; and unto them that look for him shall he appear the second time without sin unto salvation.","sources":{"KJV":{"text":"So Christ was once offered to bear the sins of many; and unto them that look for him shall he appear the second time without sin unto salvation."}},"definableWords":["sin"],"peopleInVerse":[]}}},"10":{"chapter":"10","title":"BOLDNESS TO ENTER THE HOLIEST","verses":{"1":{"text":"For the law having a shadow of good things to come, and not the very image of the things, can never with those sacrifices which they offered year by year continually make the comers thereunto perfect.","ref":"Hebrews 10:1","synthesized":"For the law having a shadow of good things to come, and not the very image of the things, can never with those sacrifices which they offered year by year continually make the comers thereunto perfect.","sources":{"KJV":{"text":"For the law having a shadow of good things to come, and not the very image of the things, can never with those sacrifices which they offered year by year continually make the comers thereunto perfect."}},"definableWords":["good","image","year","make"],"peopleInVerse":[]},"2":{"text":"For then would they not have ceased to be offered? because that the worshippers once purged should have had no more conscience of sins.","ref":"Hebrews 10:2","synthesized":"For then would they not have ceased to be offered? because that the worshippers once purged should have had no more conscience of sins.","sources":{"KJV":{"text":"For then would they not have ceased to be offered? because that the worshippers once purged should have had no more conscience of sins."}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"But in those sacrifices there is a remembrance again made of sins every year.","ref":"Hebrews 10:3","synthesized":"But in those sacrifices there is a remembrance again made of sins every year.","sources":{"KJV":{"text":"But in those sacrifices there is a remembrance again made of sins every year."}},"definableWords":["made","year"],"peopleInVerse":[]},"4":{"text":"For it is not possible that the blood of bulls and of goats should take away sins.","ref":"Hebrews 10:4","synthesized":"For it is not possible that the blood of bulls and of goats should take away sins.","sources":{"KJV":{"text":"For it is not possible that the blood of bulls and of goats should take away sins."}},"definableWords":["blood"],"peopleInVerse":[]},"5":{"text":"Wherefore when he cometh into the world, he saith, Sacrifice and offering thou wouldest not, but a body hast thou prepared me:","ref":"Hebrews 10:5","synthesized":"Wherefore when he cometh into the world, he saith, Sacrifice and offering thou wouldest not, but a body hast thou prepared me:","sources":{"KJV":{"text":"Wherefore when he cometh into the world, he saith, Sacrifice and offering thou wouldest not, but a body hast thou prepared me:"}},"definableWords":["sacrifice","offering"],"peopleInVerse":[]},"6":{"text":"In burnt offerings and sacrifices for sin thou hast had no pleasure.","ref":"Hebrews 10:6","synthesized":"In burnt offerings and sacrifices for sin thou hast had no pleasure.","sources":{"KJV":{"text":"In burnt offerings and sacrifices for sin thou hast had no pleasure."}},"definableWords":["sin"],"peopleInVerse":[]},"7":{"text":"Then said I, Lo, I come (in the volume of the book it is written of me,) to do thy will, O God.","ref":"Hebrews 10:7","synthesized":"Then said I, Lo, I come (in the volume of the book it is written of me,) to do thy will, O God.","sources":{"KJV":{"text":"Then said I, Lo, I come (in the volume of the book it is written of me,) to do thy will, O God."}},"definableWords":["God"],"peopleInVerse":[]},"8":{"text":"Above when he said, Sacrifice and offering and burnt offerings and offering for sin thou wouldest not, neither hadst pleasure therein; which are offered by the law;","ref":"Hebrews 10:8","synthesized":"Above when he said, Sacrifice and offering and burnt offerings and offering for sin thou wouldest not, neither hadst pleasure therein; which are offered by the law;","sources":{"KJV":{"text":"Above when he said, Sacrifice and offering and burnt offerings and offering for sin thou wouldest not, neither hadst pleasure therein; which are offered by the law;"}},"definableWords":["sacrifice","offering","sin"],"peopleInVerse":[]},"9":{"text":"Then said he, Lo, I come to do thy will, O God. He taketh away the first, that he may establish the second.","ref":"Hebrews 10:9","synthesized":"Then said he, Lo, I come to do thy will, O God. He taketh away the first, that he may establish the second.","sources":{"KJV":{"text":"Then said he, Lo, I come to do thy will, O God. He taketh away the first, that he may establish the second."}},"definableWords":["God"],"peopleInVerse":[]},"10":{"text":"By the which will we are sanctified through the offering of the body of Jesus Christ once for all.","ref":"Hebrews 10:10","synthesized":"By the which will we are sanctified through the offering of the body of Jesus Christ once for all.","sources":{"KJV":{"text":"By the which will we are sanctified through the offering of the body of Jesus Christ once for all."}},"definableWords":["offering"],"peopleInVerse":["Jesus"]},"11":{"text":"And every priest standeth daily ministering and offering oftentimes the same sacrifices, which can never take away sins:","ref":"Hebrews 10:11","synthesized":"And every priest standeth daily ministering and offering oftentimes the same sacrifices, which can never take away sins:","sources":{"KJV":{"text":"And every priest standeth daily ministering and offering oftentimes the same sacrifices, which can never take away sins:"}},"definableWords":["offering"],"peopleInVerse":[]},"12":{"text":"But this man, after he had offered one sacrifice for sins for ever, sat down on the right hand of God;","ref":"Hebrews 10:12","synthesized":"But this man, after he had offered one sacrifice for sins for ever, sat down on the right hand of God;","sources":{"KJV":{"text":"But this man, after he had offered one sacrifice for sins for ever, sat down on the right hand of God;"}},"definableWords":["man","one","sacrifice","God"],"peopleInVerse":[]},"13":{"text":"From henceforth expecting till his enemies be made his footstool.","ref":"Hebrews 10:13","synthesized":"From henceforth expecting till his enemies be made his footstool.","sources":{"KJV":{"text":"From henceforth expecting till his enemies be made his footstool."}},"definableWords":["till","made"],"peopleInVerse":[]},"14":{"text":"For by one offering he hath perfected for ever them that are sanctified.","ref":"Hebrews 10:14","synthesized":"For by one offering he hath perfected for ever them that are sanctified.","sources":{"KJV":{"text":"For by one offering he hath perfected for ever them that are sanctified."}},"definableWords":["one","offering"],"peopleInVerse":[]},"15":{"text":"Whereof the Holy Ghost also is a witness to us: for after that he had said before,","ref":"Hebrews 10:15","synthesized":"Whereof the Holy Ghost also is a witness to us: for after that he had said before,","sources":{"KJV":{"text":"Whereof the Holy Ghost also is a witness to us: for after that he had said before,"}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"This is the covenant that I will make with them after those days, saith the Lord, I will put my laws into their hearts, and in their minds will I write them;","ref":"Hebrews 10:16","synthesized":"This is the covenant that I will make with them after those days, saith the Lord, I will put my laws into their hearts, and in their minds will I write them;","sources":{"KJV":{"text":"This is the covenant that I will make with them after those days, saith the Lord, I will put my laws into their hearts, and in their minds will I write them;"}},"definableWords":["covenant","make","days","Lord"],"peopleInVerse":[]},"17":{"text":"And their sins and iniquities will I remember no more.","ref":"Hebrews 10:17","synthesized":"And their sins and iniquities will I remember no more.","sources":{"KJV":{"text":"And their sins and iniquities will I remember no more."}},"definableWords":["remember"],"peopleInVerse":[]},"18":{"text":"Now where remission of these is, there is no more offering for sin.","ref":"Hebrews 10:18","synthesized":"Now where remission of these is, there is no more offering for sin.","sources":{"KJV":{"text":"Now where remission of these is, there is no more offering for sin."}},"definableWords":["offering","sin"],"peopleInVerse":[]},"19":{"text":"Having therefore, brethren, boldness to enter into the holiest by the blood of Jesus,","ref":"Hebrews 10:19","synthesized":"Having therefore, brethren, boldness to enter into the holiest by the blood of Jesus,","sources":{"KJV":{"text":"Having therefore, brethren, boldness to enter into the holiest by the blood of Jesus,"}},"definableWords":["brethren","blood"],"peopleInVerse":["Jesus"]},"20":{"text":"By a new and living way, which he hath consecrated for us, through the veil, that is to say, his flesh;","ref":"Hebrews 10:20","synthesized":"By a new and living way, which he hath consecrated for us, through the veil, that is to say, his flesh;","sources":{"KJV":{"text":"By a new and living way, which he hath consecrated for us, through the veil, that is to say, his flesh;"}},"definableWords":["living","way","flesh"],"peopleInVerse":[]},"21":{"text":"And having an high priest over the house of God;","ref":"Hebrews 10:21","synthesized":"And having an high priest over the house of God;","sources":{"KJV":{"text":"And having an high priest over the house of God;"}},"definableWords":["house","God"],"peopleInVerse":[]},"22":{"text":"Let us draw near with a true heart in full assurance of faith, having our hearts sprinkled from an evil conscience, and our bodies washed with pure water.","ref":"Hebrews 10:22","synthesized":"Let us draw near with a true heart in full assurance of faith, having our hearts sprinkled from an evil conscience, and our bodies washed with pure water.","sources":{"KJV":{"text":"Let us draw near with a true heart in full assurance of faith, having our hearts sprinkled from an evil conscience, and our bodies washed with pure water."}},"definableWords":["faith","evil","water"],"peopleInVerse":[]},"23":{"text":"Let us hold fast the profession of our faith without wavering; (for he is faithful that promised;)","ref":"Hebrews 10:23","synthesized":"Let us hold fast the profession of our faith without wavering; (for he is faithful that promised;)","sources":{"KJV":{"text":"Let us hold fast the profession of our faith without wavering; (for he is faithful that promised;)"}},"definableWords":["faith"],"peopleInVerse":[]},"24":{"text":"And let us consider one another to provoke unto love and to good works:","ref":"Hebrews 10:24","synthesized":"And let us consider one another to provoke unto love and to good works:","sources":{"KJV":{"text":"And let us consider one another to provoke unto love and to good works:"}},"definableWords":["one","love","good","works"],"peopleInVerse":[]},"25":{"text":"Not forsaking the assembling of ourselves together, as the manner of some is; but exhorting one another: and so much the more, as ye see the day approaching.","ref":"Hebrews 10:25","synthesized":"Not forsaking the assembling of ourselves together, as the manner of some is; but exhorting one another: and so much the more, as ye see the day approaching.","sources":{"KJV":{"text":"Not forsaking the assembling of ourselves together, as the manner of some is; but exhorting one another: and so much the more, as ye see the day approaching."}},"definableWords":["one","see","day"],"peopleInVerse":[]},"26":{"text":"For if we sin wilfully after that we have received the knowledge of the truth, there remaineth no more sacrifice for sins,","ref":"Hebrews 10:26","synthesized":"For if we sin wilfully after that we have received the knowledge of the truth, there remaineth no more sacrifice for sins,","sources":{"KJV":{"text":"For if we sin wilfully after that we have received the knowledge of the truth, there remaineth no more sacrifice for sins,"}},"definableWords":["sin","knowledge","sacrifice"],"peopleInVerse":[]},"27":{"text":"But a certain fearful looking for of judgment and fiery indignation, which shall devour the adversaries.","ref":"Hebrews 10:27","synthesized":"But a certain fearful looking for of judgment and fiery indignation, which shall devour the adversaries.","sources":{"KJV":{"text":"But a certain fearful looking for of judgment and fiery indignation, which shall devour the adversaries."}},"definableWords":["judgment"],"peopleInVerse":[]},"28":{"text":"He that despised Moses’ law died without mercy under two or three witnesses:","ref":"Hebrews 10:28","synthesized":"He that despised Moses’ law died without mercy under two or three witnesses:","sources":{"KJV":{"text":"He that despised Moses’ law died without mercy under two or three witnesses:"}},"definableWords":["mercy","or"],"peopleInVerse":["Moses"]},"29":{"text":"Of how much sorer punishment, suppose ye, shall he be thought worthy, who hath trodden under foot the Son of God, and hath counted the blood of the covenant, wherewith he was sanctified, an unholy thing, and hath done despite unto the Spirit of grace?","ref":"Hebrews 10:29","synthesized":"Of how much sorer punishment, suppose ye, shall he be thought worthy, who hath trodden under foot the Son of God, and hath counted the blood of the covenant, wherewith he was sanctified, an unholy thing, and hath done despite unto the Spirit of grace?","sources":{"KJV":{"text":"Of how much sorer punishment, suppose ye, shall he be thought worthy, who hath trodden under foot the Son of God, and hath counted the blood of the covenant, wherewith he was sanctified, an unholy thing, and hath done despite unto the Spirit of grace?"}},"definableWords":["son","God","blood","covenant","Spirit"],"peopleInVerse":[]},"30":{"text":"For we know him that hath said, Vengeance belongeth unto me, I will recompense, saith the Lord. And again, The Lord shall judge his people.","ref":"Hebrews 10:30","synthesized":"For we know him that hath said, Vengeance belongeth unto me, I will recompense, saith the Lord. And again, The Lord shall judge his people.","sources":{"KJV":{"text":"For we know him that hath said, Vengeance belongeth unto me, I will recompense, saith the Lord. And again, The Lord shall judge his people."}},"definableWords":["Lord","people"],"peopleInVerse":[]},"31":{"text":"It is a fearful thing to fall into the hands of the living God.","ref":"Hebrews 10:31","synthesized":"It is a fearful thing to fall into the hands of the living God.","sources":{"KJV":{"text":"It is a fearful thing to fall into the hands of the living God."}},"definableWords":["living","God"],"peopleInVerse":[]},"32":{"text":"But call to remembrance the former days, in which, after ye were illuminated, ye endured a great fight of afflictions;","ref":"Hebrews 10:32","synthesized":"But call to remembrance the former days, in which, after ye were illuminated, ye endured a great fight of afflictions;","sources":{"KJV":{"text":"But call to remembrance the former days, in which, after ye were illuminated, ye endured a great fight of afflictions;"}},"definableWords":["days","great"],"peopleInVerse":[]},"33":{"text":"Partly, whilst ye were made a gazingstock both by reproaches and afflictions; and partly, whilst ye became companions of them that were so used.","ref":"Hebrews 10:33","synthesized":"Partly, whilst ye were made a gazingstock both by reproaches and afflictions; and partly, whilst ye became companions of them that were so used.","sources":{"KJV":{"text":"Partly, whilst ye were made a gazingstock both by reproaches and afflictions; and partly, whilst ye became companions of them that were so used."}},"definableWords":["made"],"peopleInVerse":[]},"34":{"text":"For ye had compassion of me in my bonds, and took joyfully the spoiling of your goods, knowing in yourselves that ye have in heaven a better and an enduring substance.","ref":"Hebrews 10:34","synthesized":"For ye had compassion of me in my bonds, and took joyfully the spoiling of your goods, knowing in yourselves that ye have in heaven a better and an enduring substance.","sources":{"KJV":{"text":"For ye had compassion of me in my bonds, and took joyfully the spoiling of your goods, knowing in yourselves that ye have in heaven a better and an enduring substance."}},"definableWords":["heaven"],"peopleInVerse":[]},"35":{"text":"Cast not away therefore your confidence, which hath great recompence of reward.","ref":"Hebrews 10:35","synthesized":"Cast not away therefore your confidence, which hath great recompence of reward.","sources":{"KJV":{"text":"Cast not away therefore your confidence, which hath great recompence of reward."}},"definableWords":["great"],"peopleInVerse":[]},"36":{"text":"For ye have need of patience, that, after ye have done the will of God, ye might receive the promise.","ref":"Hebrews 10:36","synthesized":"For ye have need of patience, that, after ye have done the will of God, ye might receive the promise.","sources":{"KJV":{"text":"For ye have need of patience, that, after ye have done the will of God, ye might receive the promise."}},"definableWords":["God","promise"],"peopleInVerse":[]},"37":{"text":"For yet a little while, and he that shall come will come, and will not tarry.","ref":"Hebrews 10:37","synthesized":"For yet a little while, and he that shall come will come, and will not tarry.","sources":{"KJV":{"text":"For yet a little while, and he that shall come will come, and will not tarry."}},"definableWords":[],"peopleInVerse":[]},"38":{"text":"Now the just shall live by faith: but if any man draw back, my soul shall have no pleasure in him.","ref":"Hebrews 10:38","synthesized":"Now the just shall live by faith: but if any man draw back, my soul shall have no pleasure in him.","sources":{"KJV":{"text":"Now the just shall live by faith: but if any man draw back, my soul shall have no pleasure in him."}},"definableWords":["live","faith","man","soul"],"peopleInVerse":[]},"39":{"text":"But we are not of them who draw back unto perdition; but of them that believe to the saving of the soul.","ref":"Hebrews 10:39","synthesized":"But we are not of them who draw back unto perdition; but of them that believe to the saving of the soul.","sources":{"KJV":{"text":"But we are not of them who draw back unto perdition; but of them that believe to the saving of the soul."}},"definableWords":["soul"],"peopleInVerse":[]}}},"11":{"chapter":"11","title":"THE HALL OF FAITH","verses":{"1":{"text":"Now faith is the substance of things hoped for, the evidence of things not seen.","ref":"Hebrews 11:1","synthesized":"Now faith is the substance of things hoped for, the evidence of things not seen.","sources":{"KJV":{"text":"Now faith is the substance of things hoped for, the evidence of things not seen."}},"definableWords":["faith"],"peopleInVerse":[],"kingdomLens":"A roll call of OT figures who lived by faith — Abel, Enoch, Noah, Abraham, Sarah, Moses, Rahab, Gideon, David, the prophets. 'These all died in faith, not having received the promises' (v.13). Then chapter 12 opens: 'Wherefore seeing we also are compassed about with so great a cloud of witnesses...' — they are watching us now, cheering us on.","cultural":{"title":"The hall of faith","detail":"Hebrews was written before AD 70 (the Temple still stands in the author's argument). The original audience was Jewish Christians under pressure to return to Judaism. The argument: Christ is greater than every OT figure and institution — but the faith of the OT saints points forward to Him.","sources":"SWRV Kingdom Study Protocol — synthesis from approved library (Rule 06)"}},"2":{"text":"For by it the elders obtained a good report.","ref":"Hebrews 11:2","synthesized":"For by it the elders obtained a good report.","sources":{"KJV":{"text":"For by it the elders obtained a good report."}},"definableWords":["good"],"peopleInVerse":[]},"3":{"text":"Through faith we understand that the worlds were framed by the word of God, so that things which are seen were not made of things which do appear.","ref":"Hebrews 11:3","synthesized":"Through faith we understand that the worlds were framed by the word of God, so that things which are seen were not made of things which do appear.","sources":{"KJV":{"text":"Through faith we understand that the worlds were framed by the word of God, so that things which are seen were not made of things which do appear."}},"definableWords":["faith","word","God","made"],"peopleInVerse":[]},"4":{"text":"By faith Abel offered unto God a more excellent sacrifice than Cain, by which he obtained witness that he was righteous, God testifying of his gifts: and by it he being dead yet speaketh.","ref":"Hebrews 11:4","synthesized":"By faith Abel offered unto God a more excellent sacrifice than Cain, by which he obtained witness that he was righteous, God testifying of his gifts: and by it he being dead yet speaketh.","sources":{"KJV":{"text":"By faith Abel offered unto God a more excellent sacrifice than Cain, by which he obtained witness that he was righteous, God testifying of his gifts: and by it he being dead yet speaketh."}},"definableWords":["faith","Abel","God","sacrifice","Cain","righteous"],"peopleInVerse":[]},"5":{"text":"By faith Enoch was translated that he should not see death; and was not found, because God had translated him: for before his translation he had this testimony, that he pleased God.","ref":"Hebrews 11:5","synthesized":"By faith Enoch was translated that he should not see death; and was not found, because God had translated him: for before his translation he had this testimony, that he pleased God.","sources":{"KJV":{"text":"By faith Enoch was translated that he should not see death; and was not found, because God had translated him: for before his translation he had this testimony, that he pleased God."}},"definableWords":["faith","Enoch","see","death","God"],"peopleInVerse":[]},"6":{"text":"But without faith it is impossible to please him: for he that cometh to God must believe that he is, and that he is a rewarder of them that diligently seek him.","ref":"Hebrews 11:6","synthesized":"But without faith it is impossible to please him: for he that cometh to God must believe that he is, and that he is a rewarder of them that diligently seek him.","sources":{"KJV":{"text":"But without faith it is impossible to please him: for he that cometh to God must believe that he is, and that he is a rewarder of them that diligently seek him."}},"definableWords":["faith","God"],"peopleInVerse":[]},"7":{"text":"By faith Noah, being warned of God of things not seen as yet, moved with fear, prepared an ark to the saving of his house; by the which he condemned the world, and became heir of the righteousness which is by faith.","ref":"Hebrews 11:7","synthesized":"By faith Noah, being warned of God of things not seen as yet, moved with fear, prepared an ark to the saving of his house; by the which he condemned the world, and became heir of the righteousness which is by faith.","sources":{"KJV":{"text":"By faith Noah, being warned of God of things not seen as yet, moved with fear, prepared an ark to the saving of his house; by the which he condemned the world, and became heir of the righteousness which is by faith."}},"definableWords":["faith","Noah","God","fear","ark","house","righteousness"],"peopleInVerse":[]},"8":{"text":"By faith Abraham, when he was called to go out into a place which he should after receive for an inheritance, obeyed; and he went out, not knowing whither he went.","ref":"Hebrews 11:8","synthesized":"By faith Abraham, when he was called to go out into a place which he should after receive for an inheritance, obeyed; and he went out, not knowing whither he went.","sources":{"KJV":{"text":"By faith Abraham, when he was called to go out into a place which he should after receive for an inheritance, obeyed; and he went out, not knowing whither he went."}},"definableWords":["faith","Abraham"],"peopleInVerse":["Abraham"]},"9":{"text":"By faith he sojourned in the land of promise, as in a strange country, dwelling in tabernacles with Isaac and Jacob, the heirs with him of the same promise:","ref":"Hebrews 11:9","synthesized":"By faith he sojourned in the land of promise, as in a strange country, dwelling in tabernacles with Isaac and Jacob, the heirs with him of the same promise:","sources":{"KJV":{"text":"By faith he sojourned in the land of promise, as in a strange country, dwelling in tabernacles with Isaac and Jacob, the heirs with him of the same promise:"}},"definableWords":["faith","land","promise","Isaac","Jacob"],"peopleInVerse":[]},"10":{"text":"For he looked for a city which hath foundations, whose builder and maker is God.","ref":"Hebrews 11:10","synthesized":"For he looked for a city which hath foundations, whose builder and maker is God.","sources":{"KJV":{"text":"For he looked for a city which hath foundations, whose builder and maker is God."}},"definableWords":["God"],"peopleInVerse":[]},"11":{"text":"Through faith also Sara herself received strength to conceive seed, and was delivered of a child when she was past age, because she judged him faithful who had promised.","ref":"Hebrews 11:11","synthesized":"Through faith also Sara herself received strength to conceive seed, and was delivered of a child when she was past age, because she judged him faithful who had promised.","sources":{"KJV":{"text":"Through faith also Sara herself received strength to conceive seed, and was delivered of a child when she was past age, because she judged him faithful who had promised."}},"definableWords":["faith","seed"],"peopleInVerse":[]},"12":{"text":"Therefore sprang there even of one, and him as good as dead, so many as the stars of the sky in multitude, and as the sand which is by the sea shore innumerable.","ref":"Hebrews 11:12","synthesized":"Therefore sprang there even of one, and him as good as dead, so many as the stars of the sky in multitude, and as the sand which is by the sea shore innumerable.","sources":{"KJV":{"text":"Therefore sprang there even of one, and him as good as dead, so many as the stars of the sky in multitude, and as the sand which is by the sea shore innumerable."}},"definableWords":["one","good","sea"],"peopleInVerse":[]},"13":{"text":"These all died in faith, not having received the promises, but having seen them afar off, and were persuaded of them, and embraced them, and confessed that they were strangers and pilgrims on the earth.","ref":"Hebrews 11:13","synthesized":"These all died in faith, not having received the promises, but having seen them afar off, and were persuaded of them, and embraced them, and confessed that they were strangers and pilgrims on the earth.","sources":{"KJV":{"text":"These all died in faith, not having received the promises, but having seen them afar off, and were persuaded of them, and embraced them, and confessed that they were strangers and pilgrims on the earth."}},"definableWords":["faith","earth"],"peopleInVerse":[]},"14":{"text":"For they that say such things declare plainly that they seek a country.","ref":"Hebrews 11:14","synthesized":"For they that say such things declare plainly that they seek a country.","sources":{"KJV":{"text":"For they that say such things declare plainly that they seek a country."}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"And truly, if they had been mindful of that country from whence they came out, they might have had opportunity to have returned.","ref":"Hebrews 11:15","synthesized":"And truly, if they had been mindful of that country from whence they came out, they might have had opportunity to have returned.","sources":{"KJV":{"text":"And truly, if they had been mindful of that country from whence they came out, they might have had opportunity to have returned."}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"But now they desire a better country, that is, an heavenly: wherefore God is not ashamed to be called their God: for he hath prepared for them a city.","ref":"Hebrews 11:16","synthesized":"But now they desire a better country, that is, an heavenly: wherefore God is not ashamed to be called their God: for he hath prepared for them a city.","sources":{"KJV":{"text":"But now they desire a better country, that is, an heavenly: wherefore God is not ashamed to be called their God: for he hath prepared for them a city."}},"definableWords":["God"],"peopleInVerse":[]},"17":{"text":"By faith Abraham, when he was tried, offered up Isaac: and he that had received the promises offered up his only begotten son,","ref":"Hebrews 11:17","synthesized":"By faith Abraham, when he was tried, offered up Isaac: and he that had received the promises offered up his only begotten son,","sources":{"KJV":{"text":"By faith Abraham, when he was tried, offered up Isaac: and he that had received the promises offered up his only begotten son,"}},"definableWords":["faith","Abraham","Isaac","son"],"peopleInVerse":["Abraham"]},"18":{"text":"Of whom it was said, That in Isaac shall thy seed be called:","ref":"Hebrews 11:18","synthesized":"Of whom it was said, That in Isaac shall thy seed be called:","sources":{"KJV":{"text":"Of whom it was said, That in Isaac shall thy seed be called:"}},"definableWords":["Isaac","seed"],"peopleInVerse":[]},"19":{"text":"Accounting that God was able to raise him up, even from the dead; from whence also he received him in a figure.","ref":"Hebrews 11:19","synthesized":"Accounting that God was able to raise him up, even from the dead; from whence also he received him in a figure.","sources":{"KJV":{"text":"Accounting that God was able to raise him up, even from the dead; from whence also he received him in a figure."}},"definableWords":["God"],"peopleInVerse":[]},"20":{"text":"By faith Isaac blessed Jacob and Esau concerning things to come.","ref":"Hebrews 11:20","synthesized":"By faith Isaac blessed Jacob and Esau concerning things to come.","sources":{"KJV":{"text":"By faith Isaac blessed Jacob and Esau concerning things to come."}},"definableWords":["faith","Isaac","blessed","Jacob","Esau"],"peopleInVerse":[]},"21":{"text":"By faith Jacob, when he was a dying, blessed both the sons of Joseph; and worshipped, leaning upon the top of his staff.","ref":"Hebrews 11:21","synthesized":"By faith Jacob, when he was a dying, blessed both the sons of Joseph; and worshipped, leaning upon the top of his staff.","sources":{"KJV":{"text":"By faith Jacob, when he was a dying, blessed both the sons of Joseph; and worshipped, leaning upon the top of his staff."}},"definableWords":["faith","Jacob","blessed","sons","Joseph"],"peopleInVerse":["Joseph"]},"22":{"text":"By faith Joseph, when he died, made mention of the departing of the children of Israel; and gave commandment concerning his bones.","ref":"Hebrews 11:22","synthesized":"By faith Joseph, when he died, made mention of the departing of the children of Israel; and gave commandment concerning his bones.","sources":{"KJV":{"text":"By faith Joseph, when he died, made mention of the departing of the children of Israel; and gave commandment concerning his bones."}},"definableWords":["faith","Joseph","made","Israel","bones"],"peopleInVerse":["Joseph"]},"23":{"text":"By faith Moses, when he was born, was hid three months of his parents, because they saw he was a proper child; and they were not afraid of the king’s commandment.","ref":"Hebrews 11:23","synthesized":"By faith Moses, when he was born, was hid three months of his parents, because they saw he was a proper child; and they were not afraid of the king’s commandment.","sources":{"KJV":{"text":"By faith Moses, when he was born, was hid three months of his parents, because they saw he was a proper child; and they were not afraid of the king’s commandment."}},"definableWords":["faith","saw","king"],"peopleInVerse":["Moses"]},"24":{"text":"By faith Moses, when he was come to years, refused to be called the son of Pharaoh’s daughter;","ref":"Hebrews 11:24","synthesized":"By faith Moses, when he was come to years, refused to be called the son of Pharaoh’s daughter;","sources":{"KJV":{"text":"By faith Moses, when he was come to years, refused to be called the son of Pharaoh’s daughter;"}},"definableWords":["faith","years","son","Pharaoh","daughter"],"peopleInVerse":["Moses"]},"25":{"text":"Choosing rather to suffer affliction with the people of God, than to enjoy the pleasures of sin for a season;","ref":"Hebrews 11:25","synthesized":"Choosing rather to suffer affliction with the people of God, than to enjoy the pleasures of sin for a season;","sources":{"KJV":{"text":"Choosing rather to suffer affliction with the people of God, than to enjoy the pleasures of sin for a season;"}},"definableWords":["people","God","sin"],"peopleInVerse":[]},"26":{"text":"Esteeming the reproach of Christ greater riches than the treasures in Egypt: for he had respect unto the recompence of the reward.","ref":"Hebrews 11:26","synthesized":"Esteeming the reproach of Christ greater riches than the treasures in Egypt: for he had respect unto the recompence of the reward.","sources":{"KJV":{"text":"Esteeming the reproach of Christ greater riches than the treasures in Egypt: for he had respect unto the recompence of the reward."}},"definableWords":["Egypt"],"peopleInVerse":[]},"27":{"text":"By faith he forsook Egypt, not fearing the wrath of the king: for he endured, as seeing him who is invisible.","ref":"Hebrews 11:27","synthesized":"By faith he forsook Egypt, not fearing the wrath of the king: for he endured, as seeing him who is invisible.","sources":{"KJV":{"text":"By faith he forsook Egypt, not fearing the wrath of the king: for he endured, as seeing him who is invisible."}},"definableWords":["faith","Egypt","wrath","king"],"peopleInVerse":[]},"28":{"text":"Through faith he kept the passover, and the sprinkling of blood, lest he that destroyed the firstborn should touch them.","ref":"Hebrews 11:28","synthesized":"Through faith he kept the passover, and the sprinkling of blood, lest he that destroyed the firstborn should touch them.","sources":{"KJV":{"text":"Through faith he kept the passover, and the sprinkling of blood, lest he that destroyed the firstborn should touch them."}},"definableWords":["faith","blood"],"peopleInVerse":[]},"29":{"text":"By faith they passed through the Red sea as by dry land: which the Egyptians assaying to do were drowned.","ref":"Hebrews 11:29","synthesized":"By faith they passed through the Red sea as by dry land: which the Egyptians assaying to do were drowned.","sources":{"KJV":{"text":"By faith they passed through the Red sea as by dry land: which the Egyptians assaying to do were drowned."}},"definableWords":["faith","sea","land"],"peopleInVerse":[]},"30":{"text":"By faith the walls of Jericho fell down, after they were compassed about seven days.","ref":"Hebrews 11:30","synthesized":"By faith the walls of Jericho fell down, after they were compassed about seven days.","sources":{"KJV":{"text":"By faith the walls of Jericho fell down, after they were compassed about seven days."}},"definableWords":["faith","days"],"peopleInVerse":[]},"31":{"text":"By faith the harlot Rahab perished not with them that believed not, when she had received the spies with peace.","ref":"Hebrews 11:31","synthesized":"By faith the harlot Rahab perished not with them that believed not, when she had received the spies with peace.","sources":{"KJV":{"text":"By faith the harlot Rahab perished not with them that believed not, when she had received the spies with peace."}},"definableWords":["faith","believed","peace"],"peopleInVerse":["Rahab"]},"32":{"text":"And what shall I more say? for the time would fail me to tell of Gedeon, and of Barak, and of Samson, and of Jephthae; of David also, and Samuel, and of the prophets:","ref":"Hebrews 11:32","synthesized":"And what shall I more say? for the time would fail me to tell of Gedeon, and of Barak, and of Samson, and of Jephthae; of David also, and Samuel, and of the prophets:","sources":{"KJV":{"text":"And what shall I more say? for the time would fail me to tell of Gedeon, and of Barak, and of Samson, and of Jephthae; of David also, and Samuel, and of the prophets:"}},"definableWords":[],"peopleInVerse":["David","Samuel"]},"33":{"text":"Who through faith subdued kingdoms, wrought righteousness, obtained promises, stopped the mouths of lions,","ref":"Hebrews 11:33","synthesized":"Who through faith subdued kingdoms, wrought righteousness, obtained promises, stopped the mouths of lions,","sources":{"KJV":{"text":"Who through faith subdued kingdoms, wrought righteousness, obtained promises, stopped the mouths of lions,"}},"definableWords":["faith","righteousness"],"peopleInVerse":[]},"34":{"text":"Quenched the violence of fire, escaped the edge of the sword, out of weakness were made strong, waxed valiant in fight, turned to flight the armies of the aliens.","ref":"Hebrews 11:34","synthesized":"Quenched the violence of fire, escaped the edge of the sword, out of weakness were made strong, waxed valiant in fight, turned to flight the armies of the aliens.","sources":{"KJV":{"text":"Quenched the violence of fire, escaped the edge of the sword, out of weakness were made strong, waxed valiant in fight, turned to flight the armies of the aliens."}},"definableWords":["made","strong"],"peopleInVerse":[]},"35":{"text":"Women received their dead raised to life again: and others were tortured, not accepting deliverance; that they might obtain a better resurrection:","ref":"Hebrews 11:35","synthesized":"Women received their dead raised to life again: and others were tortured, not accepting deliverance; that they might obtain a better resurrection:","sources":{"KJV":{"text":"Women received their dead raised to life again: and others were tortured, not accepting deliverance; that they might obtain a better resurrection:"}},"definableWords":["women","life"],"peopleInVerse":[]},"36":{"text":"And others had trial of cruel mockings and scourgings, yea, moreover of bonds and imprisonment:","ref":"Hebrews 11:36","synthesized":"And others had trial of cruel mockings and scourgings, yea, moreover of bonds and imprisonment:","sources":{"KJV":{"text":"And others had trial of cruel mockings and scourgings, yea, moreover of bonds and imprisonment:"}},"definableWords":[],"peopleInVerse":[]},"37":{"text":"They were stoned, they were sawn asunder, were tempted, were slain with the sword: they wandered about in sheepskins and goatskins; being destitute, afflicted, tormented;","ref":"Hebrews 11:37","synthesized":"They were stoned, they were sawn asunder, were tempted, were slain with the sword: they wandered about in sheepskins and goatskins; being destitute, afflicted, tormented;","sources":{"KJV":{"text":"They were stoned, they were sawn asunder, were tempted, were slain with the sword: they wandered about in sheepskins and goatskins; being destitute, afflicted, tormented;"}},"definableWords":[],"peopleInVerse":[]},"38":{"text":"(Of whom the world was not worthy:) they wandered in deserts, and in mountains, and in dens and caves of the earth.","ref":"Hebrews 11:38","synthesized":"(Of whom the world was not worthy:) they wandered in deserts, and in mountains, and in dens and caves of the earth.","sources":{"KJV":{"text":"(Of whom the world was not worthy:) they wandered in deserts, and in mountains, and in dens and caves of the earth."}},"definableWords":["earth"],"peopleInVerse":[]},"39":{"text":"And these all, having obtained a good report through faith, received not the promise:","ref":"Hebrews 11:39","synthesized":"And these all, having obtained a good report through faith, received not the promise:","sources":{"KJV":{"text":"And these all, having obtained a good report through faith, received not the promise:"}},"definableWords":["good","faith","promise"],"peopleInVerse":[]},"40":{"text":"God having provided some better thing for us, that they without us should not be made perfect.","ref":"Hebrews 11:40","synthesized":"God having provided some better thing for us, that they without us should not be made perfect.","sources":{"KJV":{"text":"God having provided some better thing for us, that they without us should not be made perfect."}},"definableWords":["God","made"],"peopleInVerse":[]}}},"12":{"chapter":"12","title":"RUN WITH PATIENCE","verses":{"1":{"text":"Wherefore seeing we also are compassed about with so great a cloud of witnesses, let us lay aside every weight, and the sin which doth so easily beset us, and let us run with patience the race that is set before us,","ref":"Hebrews 12:1","synthesized":"Wherefore seeing we also are compassed about with so great a cloud of witnesses, let us lay aside every weight, and the sin which doth so easily beset us, and let us run with patience the race that is set before us,","sources":{"KJV":{"text":"Wherefore seeing we also are compassed about with so great a cloud of witnesses, let us lay aside every weight, and the sin which doth so easily beset us, and let us run with patience the race that is set before us,"}},"definableWords":["great","sin"],"peopleInVerse":[]},"2":{"text":"Looking unto Jesus the author and finisher of our faith; who for the joy that was set before him endured the cross, despising the shame, and is set down at the right hand of the throne of God.","ref":"Hebrews 12:2","synthesized":"Looking unto Jesus the author and finisher of our faith; who for the joy that was set before him endured the cross, despising the shame, and is set down at the right hand of the throne of God.","sources":{"KJV":{"text":"Looking unto Jesus the author and finisher of our faith; who for the joy that was set before him endured the cross, despising the shame, and is set down at the right hand of the throne of God."}},"definableWords":["faith","throne","God"],"peopleInVerse":["Jesus"]},"3":{"text":"For consider him that endured such contradiction of sinners against himself, lest ye be wearied and faint in your minds.","ref":"Hebrews 12:3","synthesized":"For consider him that endured such contradiction of sinners against himself, lest ye be wearied and faint in your minds.","sources":{"KJV":{"text":"For consider him that endured such contradiction of sinners against himself, lest ye be wearied and faint in your minds."}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"Ye have not yet resisted unto blood, striving against sin.","ref":"Hebrews 12:4","synthesized":"Ye have not yet resisted unto blood, striving against sin.","sources":{"KJV":{"text":"Ye have not yet resisted unto blood, striving against sin."}},"definableWords":["blood","sin"],"peopleInVerse":[]},"5":{"text":"And ye have forgotten the exhortation which speaketh unto you as unto children, My son, despise not thou the chastening of the Lord, nor faint when thou art rebuked of him:","ref":"Hebrews 12:5","synthesized":"And ye have forgotten the exhortation which speaketh unto you as unto children, My son, despise not thou the chastening of the Lord, nor faint when thou art rebuked of him:","sources":{"KJV":{"text":"And ye have forgotten the exhortation which speaketh unto you as unto children, My son, despise not thou the chastening of the Lord, nor faint when thou art rebuked of him:"}},"definableWords":["son","Lord"],"peopleInVerse":[]},"6":{"text":"For whom the Lord loveth he chasteneth, and scourgeth every son whom he receiveth.","ref":"Hebrews 12:6","synthesized":"For whom the Lord loveth he chasteneth, and scourgeth every son whom he receiveth.","sources":{"KJV":{"text":"For whom the Lord loveth he chasteneth, and scourgeth every son whom he receiveth."}},"definableWords":["Lord","son"],"peopleInVerse":[]},"7":{"text":"If ye endure chastening, God dealeth with you as with sons; for what son is he whom the father chasteneth not?","ref":"Hebrews 12:7","synthesized":"If ye endure chastening, God dealeth with you as with sons; for what son is he whom the father chasteneth not?","sources":{"KJV":{"text":"If ye endure chastening, God dealeth with you as with sons; for what son is he whom the father chasteneth not?"}},"definableWords":["God","sons","son","father"],"peopleInVerse":[]},"8":{"text":"But if ye be without chastisement, whereof all are partakers, then are ye bastards, and not sons.","ref":"Hebrews 12:8","synthesized":"But if ye be without chastisement, whereof all are partakers, then are ye bastards, and not sons.","sources":{"KJV":{"text":"But if ye be without chastisement, whereof all are partakers, then are ye bastards, and not sons."}},"definableWords":["sons"],"peopleInVerse":[]},"9":{"text":"Furthermore we have had fathers of our flesh which corrected us, and we gave them reverence: shall we not much rather be in subjection unto the Father of spirits, and live?","ref":"Hebrews 12:9","synthesized":"Furthermore we have had fathers of our flesh which corrected us, and we gave them reverence: shall we not much rather be in subjection unto the Father of spirits, and live?","sources":{"KJV":{"text":"Furthermore we have had fathers of our flesh which corrected us, and we gave them reverence: shall we not much rather be in subjection unto the Father of spirits, and live?"}},"definableWords":["fathers","flesh","father","live"],"peopleInVerse":[]},"10":{"text":"For they verily for a few days chastened us after their own pleasure; but he for our profit, that we might be partakers of his holiness.","ref":"Hebrews 12:10","synthesized":"For they verily for a few days chastened us after their own pleasure; but he for our profit, that we might be partakers of his holiness.","sources":{"KJV":{"text":"For they verily for a few days chastened us after their own pleasure; but he for our profit, that we might be partakers of his holiness."}},"definableWords":["days"],"peopleInVerse":[]},"11":{"text":"Now no chastening for the present seemeth to be joyous, but grievous: nevertheless afterward it yieldeth the peaceable fruit of righteousness unto them which are exercised thereby.","ref":"Hebrews 12:11","synthesized":"Now no chastening for the present seemeth to be joyous, but grievous: nevertheless afterward it yieldeth the peaceable fruit of righteousness unto them which are exercised thereby.","sources":{"KJV":{"text":"Now no chastening for the present seemeth to be joyous, but grievous: nevertheless afterward it yieldeth the peaceable fruit of righteousness unto them which are exercised thereby."}},"definableWords":["righteousness"],"peopleInVerse":[]},"12":{"text":"Wherefore lift up the hands which hang down, and the feeble knees;","ref":"Hebrews 12:12","synthesized":"Wherefore lift up the hands which hang down, and the feeble knees;","sources":{"KJV":{"text":"Wherefore lift up the hands which hang down, and the feeble knees;"}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"And make straight paths for your feet, lest that which is lame be turned out of the way; but let it rather be healed.","ref":"Hebrews 12:13","synthesized":"And make straight paths for your feet, lest that which is lame be turned out of the way; but let it rather be healed.","sources":{"KJV":{"text":"And make straight paths for your feet, lest that which is lame be turned out of the way; but let it rather be healed."}},"definableWords":["make","way"],"peopleInVerse":[]},"14":{"text":"Follow peace with all men, and holiness, without which no man shall see the Lord:","ref":"Hebrews 12:14","synthesized":"Follow peace with all men, and holiness, without which no man shall see the Lord:","sources":{"KJV":{"text":"Follow peace with all men, and holiness, without which no man shall see the Lord:"}},"definableWords":["peace","men","man","see","Lord"],"peopleInVerse":[]},"15":{"text":"Looking diligently lest any man fail of the grace of God; lest any root of bitterness springing up trouble you, and thereby many be defiled;","ref":"Hebrews 12:15","synthesized":"Looking diligently lest any man fail of the grace of God; lest any root of bitterness springing up trouble you, and thereby many be defiled;","sources":{"KJV":{"text":"Looking diligently lest any man fail of the grace of God; lest any root of bitterness springing up trouble you, and thereby many be defiled;"}},"definableWords":["man","God"],"peopleInVerse":[]},"16":{"text":"Lest there be any fornicator, or profane person, as Esau, who for one morsel of meat sold his birthright.","ref":"Hebrews 12:16","synthesized":"Lest there be any fornicator, or profane person, as Esau, who for one morsel of meat sold his birthright.","sources":{"KJV":{"text":"Lest there be any fornicator, or profane person, as Esau, who for one morsel of meat sold his birthright."}},"definableWords":["or","Esau","one"],"peopleInVerse":[]},"17":{"text":"For ye know how that afterward, when he would have inherited the blessing, he was rejected: for he found no place of repentance, though he sought it carefully with tears.","ref":"Hebrews 12:17","synthesized":"For ye know how that afterward, when he would have inherited the blessing, he was rejected: for he found no place of repentance, though he sought it carefully with tears.","sources":{"KJV":{"text":"For ye know how that afterward, when he would have inherited the blessing, he was rejected: for he found no place of repentance, though he sought it carefully with tears."}},"definableWords":["blessing"],"peopleInVerse":[]},"18":{"text":"For ye are not come unto the mount that might be touched, and that burned with fire, nor unto blackness, and darkness, and tempest,","ref":"Hebrews 12:18","synthesized":"For ye are not come unto the mount that might be touched, and that burned with fire, nor unto blackness, and darkness, and tempest,","sources":{"KJV":{"text":"For ye are not come unto the mount that might be touched, and that burned with fire, nor unto blackness, and darkness, and tempest,"}},"definableWords":["darkness"],"peopleInVerse":[]},"19":{"text":"And the sound of a trumpet, and the voice of words; which voice they that heard intreated that the word should not be spoken to them any more:","ref":"Hebrews 12:19","synthesized":"And the sound of a trumpet, and the voice of words; which voice they that heard intreated that the word should not be spoken to them any more:","sources":{"KJV":{"text":"And the sound of a trumpet, and the voice of words; which voice they that heard intreated that the word should not be spoken to them any more:"}},"definableWords":["voice","word"],"peopleInVerse":[]},"20":{"text":"(For they could not endure that which was commanded, And if so much as a beast touch the mountain, it shall be stoned, or thrust through with a dart:","ref":"Hebrews 12:20","synthesized":"(For they could not endure that which was commanded, And if so much as a beast touch the mountain, it shall be stoned, or thrust through with a dart:","sources":{"KJV":{"text":"(For they could not endure that which was commanded, And if so much as a beast touch the mountain, it shall be stoned, or thrust through with a dart:"}},"definableWords":["or"],"peopleInVerse":[]},"21":{"text":"And so terrible was the sight, that Moses said, I exceedingly fear and quake:)","ref":"Hebrews 12:21","synthesized":"And so terrible was the sight, that Moses said, I exceedingly fear and quake:)","sources":{"KJV":{"text":"And so terrible was the sight, that Moses said, I exceedingly fear and quake:)"}},"definableWords":["fear"],"peopleInVerse":["Moses"]},"22":{"text":"But ye are come unto mount Sion, and unto the city of the living God, the heavenly Jerusalem, and to an innumerable company of angels,","ref":"Hebrews 12:22","synthesized":"But ye are come unto mount Sion, and unto the city of the living God, the heavenly Jerusalem, and to an innumerable company of angels,","sources":{"KJV":{"text":"But ye are come unto mount Sion, and unto the city of the living God, the heavenly Jerusalem, and to an innumerable company of angels,"}},"definableWords":["living","God"],"peopleInVerse":[]},"23":{"text":"To the general assembly and church of the firstborn, which are written in heaven, and to God the Judge of all, and to the spirits of just men made perfect,","ref":"Hebrews 12:23","synthesized":"To the general assembly and church of the firstborn, which are written in heaven, and to God the Judge of all, and to the spirits of just men made perfect,","sources":{"KJV":{"text":"To the general assembly and church of the firstborn, which are written in heaven, and to God the Judge of all, and to the spirits of just men made perfect,"}},"definableWords":["heaven","God","men","made"],"peopleInVerse":[]},"24":{"text":"And to Jesus the mediator of the new covenant, and to the blood of sprinkling, that speaketh better things than that of Abel.","ref":"Hebrews 12:24","synthesized":"And to Jesus the mediator of the new covenant, and to the blood of sprinkling, that speaketh better things than that of Abel.","sources":{"KJV":{"text":"And to Jesus the mediator of the new covenant, and to the blood of sprinkling, that speaketh better things than that of Abel."}},"definableWords":["covenant","blood","Abel"],"peopleInVerse":["Jesus"]},"25":{"text":"See that ye refuse not him that speaketh. For if they escaped not who refused him that spake on earth, much more shall not we escape, if we turn away from him that speaketh from heaven:","ref":"Hebrews 12:25","synthesized":"See that ye refuse not him that speaketh. For if they escaped not who refused him that spake on earth, much more shall not we escape, if we turn away from him that speaketh from heaven:","sources":{"KJV":{"text":"See that ye refuse not him that speaketh. For if they escaped not who refused him that spake on earth, much more shall not we escape, if we turn away from him that speaketh from heaven:"}},"definableWords":["see","earth","heaven"],"peopleInVerse":[]},"26":{"text":"Whose voice then shook the earth: but now he hath promised, saying, Yet once more I shake not the earth only, but also heaven.","ref":"Hebrews 12:26","synthesized":"Whose voice then shook the earth: but now he hath promised, saying, Yet once more I shake not the earth only, but also heaven.","sources":{"KJV":{"text":"Whose voice then shook the earth: but now he hath promised, saying, Yet once more I shake not the earth only, but also heaven."}},"definableWords":["voice","earth","heaven"],"peopleInVerse":[]},"27":{"text":"And this word, Yet once more, signifieth the removing of those things that are shaken, as of things that are made, that those things which cannot be shaken may remain.","ref":"Hebrews 12:27","synthesized":"And this word, Yet once more, signifieth the removing of those things that are shaken, as of things that are made, that those things which cannot be shaken may remain.","sources":{"KJV":{"text":"And this word, Yet once more, signifieth the removing of those things that are shaken, as of things that are made, that those things which cannot be shaken may remain."}},"definableWords":["word","made"],"peopleInVerse":[]},"28":{"text":"Wherefore we receiving a kingdom which cannot be moved, let us have grace, whereby we may serve God acceptably with reverence and godly fear:","ref":"Hebrews 12:28","synthesized":"Wherefore we receiving a kingdom which cannot be moved, let us have grace, whereby we may serve God acceptably with reverence and godly fear:","sources":{"KJV":{"text":"Wherefore we receiving a kingdom which cannot be moved, let us have grace, whereby we may serve God acceptably with reverence and godly fear:"}},"definableWords":["kingdom","God","fear"],"peopleInVerse":[]},"29":{"text":"For our God is a consuming fire.","ref":"Hebrews 12:29","synthesized":"For our God is a consuming fire.","sources":{"KJV":{"text":"For our God is a consuming fire."}},"definableWords":["God"],"peopleInVerse":[]}}},"13":{"chapter":"13","title":"JESUS CHRIST, THE SAME YESTERDAY, TODAY, FOREVER","verses":{"1":{"text":"Let brotherly love continue.","ref":"Hebrews 13:1","synthesized":"Let brotherly love continue.","sources":{"KJV":{"text":"Let brotherly love continue."}},"definableWords":["love"],"peopleInVerse":[]},"2":{"text":"Be not forgetful to entertain strangers: for thereby some have entertained angels unawares.","ref":"Hebrews 13:2","synthesized":"Be not forgetful to entertain strangers: for thereby some have entertained angels unawares.","sources":{"KJV":{"text":"Be not forgetful to entertain strangers: for thereby some have entertained angels unawares."}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"Remember them that are in bonds, as bound with them; and them which suffer adversity, as being yourselves also in the body.","ref":"Hebrews 13:3","synthesized":"Remember them that are in bonds, as bound with them; and them which suffer adversity, as being yourselves also in the body.","sources":{"KJV":{"text":"Remember them that are in bonds, as bound with them; and them which suffer adversity, as being yourselves also in the body."}},"definableWords":["remember"],"peopleInVerse":[]},"4":{"text":"Marriage is honourable in all, and the bed undefiled: but whoremongers and adulterers God will judge.","ref":"Hebrews 13:4","synthesized":"Marriage is honourable in all, and the bed undefiled: but whoremongers and adulterers God will judge.","sources":{"KJV":{"text":"Marriage is honourable in all, and the bed undefiled: but whoremongers and adulterers God will judge."}},"definableWords":["God"],"peopleInVerse":[]},"5":{"text":"Let your conversation be without covetousness; and be content with such things as ye have: for he hath said, I will never leave thee, nor forsake thee.","ref":"Hebrews 13:5","synthesized":"Let your conversation be without covetousness; and be content with such things as ye have: for he hath said, I will never leave thee, nor forsake thee.","sources":{"KJV":{"text":"Let your conversation be without covetousness; and be content with such things as ye have: for he hath said, I will never leave thee, nor forsake thee."}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"So that we may boldly say, The Lord is my helper, and I will not fear what man shall do unto me.","ref":"Hebrews 13:6","synthesized":"So that we may boldly say, The Lord is my helper, and I will not fear what man shall do unto me.","sources":{"KJV":{"text":"So that we may boldly say, The Lord is my helper, and I will not fear what man shall do unto me."}},"definableWords":["Lord","helper","fear","man"],"peopleInVerse":[]},"7":{"text":"Remember them which have the rule over you, who have spoken unto you the word of God: whose faith follow, considering the end of their conversation.","ref":"Hebrews 13:7","synthesized":"Remember them which have the rule over you, who have spoken unto you the word of God: whose faith follow, considering the end of their conversation.","sources":{"KJV":{"text":"Remember them which have the rule over you, who have spoken unto you the word of God: whose faith follow, considering the end of their conversation."}},"definableWords":["remember","rule","word","God","faith"],"peopleInVerse":[]},"8":{"text":"Jesus Christ the same yesterday, and to day, and for ever.","ref":"Hebrews 13:8","synthesized":"Jesus Christ the same yesterday, and to day, and for ever.","sources":{"KJV":{"text":"Jesus Christ the same yesterday, and to day, and for ever."}},"definableWords":["day"],"peopleInVerse":["Jesus"]},"9":{"text":"Be not carried about with divers and strange doctrines. For it is a good thing that the heart be established with grace; not with meats, which have not profited them that have been occupied therein.","ref":"Hebrews 13:9","synthesized":"Be not carried about with divers and strange doctrines. For it is a good thing that the heart be established with grace; not with meats, which have not profited them that have been occupied therein.","sources":{"KJV":{"text":"Be not carried about with divers and strange doctrines. For it is a good thing that the heart be established with grace; not with meats, which have not profited them that have been occupied therein."}},"definableWords":["good"],"peopleInVerse":[]},"10":{"text":"We have an altar, whereof they have no right to eat which serve the tabernacle.","ref":"Hebrews 13:10","synthesized":"We have an altar, whereof they have no right to eat which serve the tabernacle.","sources":{"KJV":{"text":"We have an altar, whereof they have no right to eat which serve the tabernacle."}},"definableWords":["altar"],"peopleInVerse":[]},"11":{"text":"For the bodies of those beasts, whose blood is brought into the sanctuary by the high priest for sin, are burned without the camp.","ref":"Hebrews 13:11","synthesized":"For the bodies of those beasts, whose blood is brought into the sanctuary by the high priest for sin, are burned without the camp.","sources":{"KJV":{"text":"For the bodies of those beasts, whose blood is brought into the sanctuary by the high priest for sin, are burned without the camp."}},"definableWords":["blood","sin"],"peopleInVerse":[]},"12":{"text":"Wherefore Jesus also, that he might sanctify the people with his own blood, suffered without the gate.","ref":"Hebrews 13:12","synthesized":"Wherefore Jesus also, that he might sanctify the people with his own blood, suffered without the gate.","sources":{"KJV":{"text":"Wherefore Jesus also, that he might sanctify the people with his own blood, suffered without the gate."}},"definableWords":["people","blood"],"peopleInVerse":["Jesus"]},"13":{"text":"Let us go forth therefore unto him without the camp, bearing his reproach.","ref":"Hebrews 13:13","synthesized":"Let us go forth therefore unto him without the camp, bearing his reproach.","sources":{"KJV":{"text":"Let us go forth therefore unto him without the camp, bearing his reproach."}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"For here have we no continuing city, but we seek one to come.","ref":"Hebrews 13:14","synthesized":"For here have we no continuing city, but we seek one to come.","sources":{"KJV":{"text":"For here have we no continuing city, but we seek one to come."}},"definableWords":["one"],"peopleInVerse":[]},"15":{"text":"By him therefore let us offer the sacrifice of praise to God continually, that is, the fruit of our lips giving thanks to his name.","ref":"Hebrews 13:15","synthesized":"By him therefore let us offer the sacrifice of praise to God continually, that is, the fruit of our lips giving thanks to his name.","sources":{"KJV":{"text":"By him therefore let us offer the sacrifice of praise to God continually, that is, the fruit of our lips giving thanks to his name."}},"definableWords":["sacrifice","God","name"],"peopleInVerse":[]},"16":{"text":"But to do good and to communicate forget not: for with such sacrifices God is well pleased.","ref":"Hebrews 13:16","synthesized":"But to do good and to communicate forget not: for with such sacrifices God is well pleased.","sources":{"KJV":{"text":"But to do good and to communicate forget not: for with such sacrifices God is well pleased."}},"definableWords":["good","God"],"peopleInVerse":[]},"17":{"text":"Obey them that have the rule over you, and submit yourselves: for they watch for your souls, as they that must give account, that they may do it with joy, and not with grief: for that is unprofitable for you.","ref":"Hebrews 13:17","synthesized":"Obey them that have the rule over you, and submit yourselves: for they watch for your souls, as they that must give account, that they may do it with joy, and not with grief: for that is unprofitable for you.","sources":{"KJV":{"text":"Obey them that have the rule over you, and submit yourselves: for they watch for your souls, as they that must give account, that they may do it with joy, and not with grief: for that is unprofitable for you."}},"definableWords":["rule"],"peopleInVerse":[]},"18":{"text":"Pray for us: for we trust we have a good conscience, in all things willing to live honestly.","ref":"Hebrews 13:18","synthesized":"Pray for us: for we trust we have a good conscience, in all things willing to live honestly.","sources":{"KJV":{"text":"Pray for us: for we trust we have a good conscience, in all things willing to live honestly."}},"definableWords":["good","live"],"peopleInVerse":[]},"19":{"text":"But I beseech you the rather to do this, that I may be restored to you the sooner.","ref":"Hebrews 13:19","synthesized":"But I beseech you the rather to do this, that I may be restored to you the sooner.","sources":{"KJV":{"text":"But I beseech you the rather to do this, that I may be restored to you the sooner."}},"definableWords":[],"peopleInVerse":[]},"20":{"text":"Now the God of peace, that brought again from the dead our Lord Jesus, that great shepherd of the sheep, through the blood of the everlasting covenant,","ref":"Hebrews 13:20","synthesized":"Now the God of peace, that brought again from the dead our Lord Jesus, that great shepherd of the sheep, through the blood of the everlasting covenant,","sources":{"KJV":{"text":"Now the God of peace, that brought again from the dead our Lord Jesus, that great shepherd of the sheep, through the blood of the everlasting covenant,"}},"definableWords":["God","peace","Lord","great","blood","covenant"],"peopleInVerse":["Jesus"]},"21":{"text":"Make you perfect in every good work to do his will, working in you that which is wellpleasing in his sight, through Jesus Christ; to whom be glory for ever and ever. Amen.","ref":"Hebrews 13:21","synthesized":"Make you perfect in every good work to do his will, working in you that which is wellpleasing in his sight, through Jesus Christ; to whom be glory for ever and ever. Amen.","sources":{"KJV":{"text":"Make you perfect in every good work to do his will, working in you that which is wellpleasing in his sight, through Jesus Christ; to whom be glory for ever and ever. Amen."}},"definableWords":["make","good","work"],"peopleInVerse":["Jesus"]},"22":{"text":"And I beseech you, brethren, suffer the word of exhortation: for I have written a letter unto you in few words.","ref":"Hebrews 13:22","synthesized":"And I beseech you, brethren, suffer the word of exhortation: for I have written a letter unto you in few words.","sources":{"KJV":{"text":"And I beseech you, brethren, suffer the word of exhortation: for I have written a letter unto you in few words."}},"definableWords":["brethren","word"],"peopleInVerse":[]},"23":{"text":"Know ye that our brother Timothy is set at liberty; with whom, if he come shortly, I will see you.","ref":"Hebrews 13:23","synthesized":"Know ye that our brother Timothy is set at liberty; with whom, if he come shortly, I will see you.","sources":{"KJV":{"text":"Know ye that our brother Timothy is set at liberty; with whom, if he come shortly, I will see you."}},"definableWords":["brother","see"],"peopleInVerse":[]},"24":{"text":"Salute all them that have the rule over you, and all the saints. They of Italy salute you.","ref":"Hebrews 13:24","synthesized":"Salute all them that have the rule over you, and all the saints. They of Italy salute you.","sources":{"KJV":{"text":"Salute all them that have the rule over you, and all the saints. They of Italy salute you."}},"definableWords":["rule"],"peopleInVerse":[]},"25":{"text":"Grace be with you all. Amen.","ref":"Hebrews 13:25","synthesized":"Grace be with you all. Amen.","sources":{"KJV":{"text":"Grace be with you all. Amen."}},"definableWords":[],"peopleInVerse":[]}}}};